@app.route('/forgot-password', methods=['GET', 'POST'])
def forgot_password():
    """Forgot password — sends reset email."""
    lang = request.args.get('lang', session.get('lang', 'en'))
    if request.method == 'POST':
        email = request.form.get('email', '').strip().lower()
        if not email:
            return render_template('login.html', lang=lang, txt=get_text(lang),
                                   error_forgot='Please enter your email address.')
        with get_db() as conn:
            user = conn.execute(
                'SELECT id, username, email FROM users WHERE LOWER(email) = ?', (email,)
            ).fetchone()
        if user:
            import secrets, hashlib
            raw_token = secrets.token_urlsafe(32)
            token_hash = hashlib.sha256(raw_token.encode()).hexdigest()
            expiry = datetime.utcnow() + timedelta(minutes=config.PASSWORD_RESET_EXPIRY)
            with get_db() as conn:
                conn.execute(
                    'UPDATE users SET reset_token = ?, reset_token_expiry = ? WHERE id = ?',
                    (token_hash, expiry.isoformat(), user['id'])
                )
                conn.commit()
            send_password_reset_email(user['email'], raw_token, user['username'])
        # Always show success (security: don't reveal if email exists)
        return render_template('login.html', lang=lang, txt=get_text(lang),
                               success_forgot='If that email exists, a reset link has been sent.')
    return render_template('login.html', lang=lang, txt=get_text(lang), show_forgot=True)

@app.route('/reset-password', methods=['GET', 'POST'])
def reset_password():
    """Reset password with valid token."""
    lang = request.args.get('lang', session.get('lang', 'en'))
    token = request.args.get('token', '') or request.form.get('token', '')
    error = None
    if not token:
        return redirect(url_for('login'))
    if request.method == 'POST':
        new_password = request.form.get('password', '')
        confirm = request.form.get('confirm_password', '')
        if not new_password or len(new_password) < 8:
            error = 'Password must be at least 8 characters.'
        elif new_password != confirm:
            error = 'Passwords do not match.'
        else:
            import hashlib
            token_hash = hashlib.sha256(token.encode()).hexdigest()
            with get_db() as conn:
                user = conn.execute(
                    'SELECT id, username FROM users WHERE reset_token = ? AND reset_token_expiry > ?',
                    (token_hash, datetime.utcnow().isoformat())
                ).fetchone()
                if not user:
                    error = 'Reset link is invalid or has expired. Please request a new one.'
                else:
                    conn.execute(
                        'UPDATE users SET password_hash = ?, reset_token = NULL, reset_token_expiry = NULL WHERE id = ?',
                        (hash_password(new_password), user['id'])
                    )
                    conn.commit()
                    log_action(user['id'], 'password_reset', {})
            if not error:
                return render_template('login.html', lang=lang, txt=get_text(lang),
                                       success='Password reset successfully. You may now log in.')
    return render_template('login.html', lang=lang, txt=get_text(lang),
                           show_reset=True, reset_token=token, error=error)

