@app.route('/api/document/<doc_type>/<int:doc_id>', methods=['PUT'])
@login_required
def api_update_document(doc_type, doc_id):
    """Inline update (edit) a document's content — User Command Center."""
    user_id = session['user_id']
    conn = get_db()
    data = request.json or {}
    new_content = data.get('content', '').strip()
    if not new_content:
        return jsonify({'success': False, 'error': 'Content is required'}), 400

    try:
        if doc_type == 'strategy':
            conn.execute('UPDATE strategies SET content = ? WHERE id = ? AND user_id = ?', (new_content, doc_id, user_id))
        elif doc_type == 'policy':
            conn.execute('UPDATE policies SET content = ? WHERE id = ? AND user_id = ?', (new_content, doc_id, user_id))
        elif doc_type == 'audit':
            conn.execute('UPDATE audits SET content = ? WHERE id = ? AND user_id = ?', (new_content, doc_id, user_id))
        elif doc_type == 'risk':
            conn.execute('UPDATE risks SET analysis = ? WHERE id = ? AND user_id = ?', (new_content, doc_id, user_id))
        else:
            return jsonify({'success': False, 'error': 'Unknown document type'}), 400
        conn.commit()
        log_action(user_id, 'inline_edit_document', {'doc_type': doc_type, 'doc_id': doc_id})
        return jsonify({'success': True, 'message': 'Document updated'})
    except Exception as e:
        print(f"Inline edit error: {e}", flush=True)
        return jsonify({'success': False, 'error': str(e)}), 500


