def diagnose_org_gaps(org_profile, domain, frameworks, lang='en'):
    """
    Pre-pass diagnostic: derive organization-specific gaps from actual user input.

    A Big-4 consultant never arrives with a fixed gap list.  They read the
    client's profile — sector, size, maturity, existing technologies, stated
    challenges — and reason about which gaps exist and why they matter for
    this specific organization under its specific regulatory obligations.

    This function does exactly that as a focused AI call before the main
    strategy generation.  Its output replaces the hardcoded domain_gaps_en/ar
    lookup and is injected verbatim into the strategy prompt so the AI writes
    about THIS organization, not a generic template.

    Returns a list of dicts: [{name, description, priority, rationale}]
    Falls back to domain defaults if the AI call fails.
    """
    org_name     = org_profile.get('org_name', 'The Organization')
    sector       = org_profile.get('sector', 'General')
    size         = org_profile.get('size', 'Medium')
    maturity     = org_profile.get('maturity_level', 'initial')
    org_struct   = org_profile.get('org_structure', 'Not specified')
    technologies = org_profile.get('technologies', [])
    challenges   = org_profile.get('challenges', 'Not specified')
    budget       = org_profile.get('budget', 'Not specified')

    tech_str = ', '.join(technologies) if technologies else 'None stated'

    if lang == 'ar':
        diag_prompt = f"""أنت خبير GRC كبير يجري تقييماً تشخيصياً أولياً لمنظمة قبل إعداد الاستراتيجية.

بيانات المنظمة:
- الاسم: {org_name}
- القطاع: {sector}
- الحجم: {size}
- مستوى النضج الحالي: {maturity}
- الهيكل التنظيمي: {org_struct}
- التقنيات القائمة: {tech_str}
- التحديات المُعلنة: {challenges}
- الميزانية: {budget}
- الإطار التنظيمي المُطبَّق: {frameworks}
- المجال: {domain}

مهمتك: حدد 5 إلى 7 فجوات حقيقية وخاصة بهذه المنظمة بالذات — ليست قائمة عامة، بل استنتاج مبني على:
1. مستوى النضج (maturity = {maturity} يعني أن الأساسيات غائبة أو ضعيفة)
2. القطاع ومتطلباته التنظيمية المحددة من {frameworks}
3. التقنيات المُستخدمة وما تكشفه من ثغرات
4. الهيكل التنظيمي وما يغيب فيه
5. التحديات المُعلنة

لكل فجوة اكتب سطراً واحداً بالصيغة التالية (JSON):
{{"name": "اسم الفجوة", "description": "وصف تفصيلي يربطها بوضع المنظمة تحديداً", "priority": "critical|high|medium", "rationale": "لماذا هذه الفجوة موجودة بناءً على بيانات المنظمة + متطلب {frameworks} المحدد"}}

أعد مصفوفة JSON فقط — بدون أي نص آخر قبلها أو بعدها.
مثال:
[{{"name": "غياب إطار حوكمة البيانات", "description": "لا يوجد هيكل رسمي لملكية البيانات أو سياسات جودتها", "priority": "critical", "rationale": "مستوى النضج الأولي يعني أن الأساس غائب؛ نظام PDPL يلزم تعيين مسؤول حماية بيانات ووضع سياسات معتمدة"}}]"""
    else:
        diag_prompt = f"""You are a senior GRC consultant conducting an initial diagnostic assessment before strategy development.

Organization Profile:
- Name: {org_name}
- Sector: {sector}
- Size: {size}
- Current Maturity Level: {maturity}
- Organizational Structure: {org_struct}
- Existing Technologies: {tech_str}
- Stated Challenges: {challenges}
- Budget Range: {budget}
- Applicable Regulatory Framework: {frameworks}
- Domain: {domain}

Your task: Identify 5 to 7 real, organization-specific gaps — not a generic checklist, but reasoned conclusions based on:
1. Maturity level (maturity = {maturity} signals foundational capabilities are absent or weak)
2. Sector-specific regulatory obligations under {frameworks}
3. Technology stack — what it reveals about existing controls and what is missing
4. Organizational structure — what is absent from it
5. Stated challenges — what they imply about systemic weaknesses

For each gap, produce one line in this exact JSON format:
{{"name": "Gap name", "description": "Specific description tying this gap to this organization's actual situation", "priority": "critical|high|medium", "rationale": "Why this gap exists given the org profile + the specific {frameworks} requirement it violates"}}

Return a JSON array ONLY — no text before or after it.
Example:
[{{"name": "Absence of Formal Risk Assessment Methodology", "description": "No documented process for identifying, rating, or treating risks across business units", "priority": "critical", "rationale": "Initial maturity with no stated risk tooling; {frameworks} mandates a documented risk assessment process as a prerequisite for all other controls"}}]"""

    try:
        raw = generate_ai_content(diag_prompt, lang, task_type='generate', content_type='diagnostic')
        if raw:
            import re as _re_diag, json as _json_diag
            # Extract JSON array from response
            m = _re_diag.search(r'\[[\s\S]*\]', raw)
            if m:
                gaps = _json_diag.loads(m.group(0))
                if isinstance(gaps, list) and len(gaps) >= 3:
                    print(f"✅ Diagnostic gaps: {len(gaps)} org-specific gaps identified", flush=True)
                    return gaps
    except Exception as e:
        print(f"⚠ Diagnostic gap call failed (non-fatal): {e}", flush=True)

    # Fallback: return None so caller uses domain defaults
    return None


