# ============================================================================

# ── Async strategy task store (mirrors _export_store pattern) ────────────────
_strategy_store: dict = {}


@app.route('/api/generate-strategy-async', methods=['POST'])
@login_required
def api_generate_strategy_async():
    """Start strategy generation in a background thread; return task_id immediately.
    Mirrors the async PDF/DOCX pattern to avoid Render's 30-second proxy timeout.
    Strategy generation takes 45-90s — the sync route is reliably killed by Render.
    """
    import uuid, threading

    try:
        data = request.get_json(force=True) or {}
    except Exception:
        return jsonify({'error': 'Invalid JSON'}), 400

    if not data.get('domain'):
        return jsonify({'error': 'domain required'}), 400

    # Check usage limit BEFORE starting thread (fail-fast, keeps limit enforcement sync)
    domain = data.get('domain', 'Cyber Security')
    try:
        can_generate, used, limit = check_usage_limit(session['user_id'], 'strategies', domain)
        if not can_generate:
            return jsonify({
                'success': False,
                'error': f'Usage limit reached for {domain}. You have used {used}/{limit} strategies.',
                'limit_reached': True
            }), 429
    except Exception:
        pass  # Non-fatal: let thread handle it

    task_id   = str(uuid.uuid4())
    _user_id  = session.get('user_id', 1)
    _data     = data
    _task_id  = task_id

    _strategy_store[task_id] = {'status': 'pending'}

    def _run():
        try:
            with app.test_request_context(
                '/api/generate-strategy',
                method='POST',
                json=_data,
                headers={'Content-Type': 'application/json'}
            ):
                from flask import session as _sess
                _sess['user_id'] = _user_id
                resp = api_generate_strategy()

            # api_generate_strategy returns jsonify({...}) — extract the dict
            if isinstance(resp, tuple):
                resp_obj, status_code = resp[0], resp[1]
                try:
                    result = resp_obj.get_json()
                except Exception:
                    result = {'success': False, 'error': 'Generation failed'}
            else:
                try:
                    result = resp.get_json()
                except Exception:
                    result = {'success': False, 'error': 'Parse failed'}

            _strategy_store[_task_id] = {
                'status': 'done',
                'result': result
            }
            print(f"ASYNC STRATEGY: task {_task_id[:8]} done — success={result.get('success')}", flush=True)

        except Exception as exc:
            print(f"ASYNC STRATEGY ERROR: {exc}", flush=True)
            _strategy_store[_task_id] = {'status': 'error', 'error': str(exc)}

    threading.Thread(target=_run, daemon=True).start()
    return jsonify({'task_id': task_id})


@app.route('/api/strategy-status/<task_id>')
@login_required
def api_strategy_status(task_id):
    """Poll async strategy task status."""
    entry = _strategy_store.get(task_id)
    if not entry:
        return jsonify({'status': 'not_found'}), 404
    status = entry.get('status', 'pending')
    if status == 'done':
        # Return full result inline (sections JSON, not a file)
        return jsonify({'status': 'done', 'result': entry.get('result', {})})
    elif status == 'error':
        return jsonify({'status': 'error', 'error': entry.get('error', 'Unknown')}), 500
    return jsonify({'status': 'pending'})


# ── Master strategy task store ────────────────────────────────────────────────
_master_store: dict = {}


def get_master_strategy_context(user_id):
    """Pull gaps, KPIs, initiatives and risks from ALL five domains for master synthesis."""
    DOMAINS = [
        'Cyber Security', 'Data Management', 'Artificial Intelligence',
        'Digital Transformation', 'Enterprise Risk Management'
    ]
    DOMAIN_LABELS = {
        'Cyber Security':             'NCA Cybersecurity',
        'Data Management':            'NDMO Data Management',
        'Artificial Intelligence':    'SDAIA AI Governance',
        'Digital Transformation':     'DGA Digital Transformation',
        'Enterprise Risk Management': 'ERM',
    }
    FRAMEWORK_MAP = {
        'Cyber Security':             'NCA ECC / NCA DCC / NCA TCC / NCA OSMACC / NCA CCC',
        'Data Management':            'NDMO / PDPL',
        'Artificial Intelligence':    'SDAIA AI Ethics / Saudi AI Strategy',
        'Digital Transformation':     'DGA / Saudi Vision 2030 Digital Government',
        'Enterprise Risk Management': 'COSO ERM / ISO 31000',
    }
    try:
        conn = get_db()
        ctx_parts = []
        domain_summaries = {}

        for domain in DOMAINS:
            label = DOMAIN_LABELS[domain]
            fw    = FRAMEWORK_MAP[domain]

            gaps = conn.execute(
                """SELECT title, description FROM project_tasks
                   WHERE user_id=? AND domain=? AND category='gap_mitigation'
                   AND source_type='ai_json_sync' ORDER BY id DESC LIMIT 6""",
                (user_id, domain)
            ).fetchall()
            kpis = conn.execute(
                """SELECT name, target_value, timeframe FROM kpis
                   WHERE user_id=? AND domain=? AND source_type='ai_json_sync'
                   ORDER BY id DESC LIMIT 5""",
                (user_id, domain)
            ).fetchall()
            inits = conn.execute(
                """SELECT title FROM project_tasks
                   WHERE user_id=? AND domain=? AND category='strategic_initiative'
                   AND source_type='ai_json_sync' ORDER BY id DESC LIMIT 5""",
                (user_id, domain)
            ).fetchall()
            risks = conn.execute(
                """SELECT name FROM risk_register
                   WHERE user_id=? AND domain=? AND source_type='ai_json_sync'
                   ORDER BY id DESC LIMIT 4""",
                (user_id, domain)
            ).fetchall()

            if not gaps and not kpis and not inits and not risks:
                # Try pulling from raw strategy content as fallback
                raw = conn.execute(
                    """SELECT content FROM strategies WHERE user_id=? AND domain=?
                       ORDER BY created_at DESC LIMIT 1""",
                    (user_id, domain)
                ).fetchone()
                if raw and raw['content']:
                    domain_summaries[domain] = {
                        'label': label, 'fw': fw,
                        'has_data': True, 'raw_snippet': raw['content'][:2000],
                        'gaps': [], 'kpis': [], 'inits': [], 'risks': []
                    }
                else:
                    domain_summaries[domain] = {'label': label, 'fw': fw, 'has_data': False}
                continue

            domain_summaries[domain] = {
                'label': label, 'fw': fw, 'has_data': True,
                'gaps':  [r['title'] for r in gaps],
                'kpis':  [(r['name'], r['target_value'], r['timeframe']) for r in kpis],
                'inits': [r['title'] for r in inits],
                'risks': [r['name']  for r in risks],
            }

        # Build structured context block
        for domain, d in domain_summaries.items():
            if not d['has_data']:
                continue
            block = [f"\n{'='*50}", f"DOMAIN: {d['label']} | Framework: {d['fw']}"]
            if d.get('gaps'):
                block.append("Key Gaps: " + " | ".join(d['gaps']))
            if d.get('kpis'):
                block.append("North Star KPIs: " + " | ".join(
                    f"{k[0]} → target {k[1]} by {k[2]}" for k in d['kpis']))
            if d.get('inits'):
                block.append("Strategic Initiatives: " + " | ".join(d['inits']))
            if d.get('risks'):
                block.append("Top Risks: " + " | ".join(d['risks']))
            if d.get('raw_snippet'):
                block.append("Strategy Excerpt:\n" + d['raw_snippet'])
            ctx_parts.append('\n'.join(block))

        return '\n'.join(ctx_parts), domain_summaries

    except Exception as e:
        print(f"get_master_strategy_context error: {e}", flush=True)
        return '', {}


