        # If still not enough parts, try splitting by numbered headers without ##
        if len(parts) < 4:
            # Try matching "1. الرؤية" or "1. Vision" at start of line
            section_split_pattern = r'(?=^[1-6]\.\s*(?:الرؤية|تحليل|الركائز|خارطة|مؤشرات|تقييم|Vision|Gap|Strategic|Implementation|Key|Confidence))'
            parts = re.split(section_split_pattern, content, flags=re.MULTILINE | re.IGNORECASE)
            parts = [p for p in parts if p.strip()]
            print(f"DEBUG: Split by numbered pattern, got {len(parts)} parts", flush=True)
        
        # Last resort: split by any "## " followed by a number
        if len(parts) < 4:
            parts = re.split(r'(?=##\s+\d)', content)
            parts = [p for p in parts if p.strip()]
            print(f"DEBUG: Split by ## + number, got {len(parts)} parts", flush=True)
        
        # Clean parts
        parts = [p.strip() for p in parts if p.strip()]
        print(f"DEBUG: Final number of parts after cleaning: {len(parts)}", flush=True)
        
        # Print first 100 chars of each part for debugging
        for i, part in enumerate(parts[:6]):
            print(f"DEBUG: Part {i} starts with: {part[:100]}", flush=True)
        
        def fix_formatting(text, lang_code):
            """Fix markdown formatting - add ### before tables and ## before section headers."""
            import re
            lines = text.split('\n')
            fixed_lines = []
            
            for i, line in enumerate(lines):
                stripped = line.strip()
                
                # Skip empty lines
                if not stripped:
                    fixed_lines.append(line)
                    continue
                
                # Skip if already has ## or ###
                if stripped.startswith('##'):
                    fixed_lines.append(line)
                    continue
                
                # Check if this is a main section header (like "1. Vision & Objectives")
                if re.match(r'^[1-6]\.\s+\w', stripped):
                    # Add ## before the section number
                    fixed_lines.append('## ' + stripped)
                    continue
                
                # Check if this line ends with : and next non-empty line is a table
                if stripped.endswith(':') and not stripped.startswith('**'):
                    # Look ahead for table
                    next_line_idx = i + 1
                    while next_line_idx < len(lines) and not lines[next_line_idx].strip():
                        next_line_idx += 1
                    
                    if next_line_idx < len(lines):
                        next_line = lines[next_line_idx].strip()
                        # Check if next line is a table header (starts with |)
                        if next_line.startswith('|'):
                            # This is a table header without ###, add it
                            fixed_lines.append('### ' + stripped)
                            continue
                
                fixed_lines.append(line)
            
            return '\n'.join(fixed_lines)
        
        # Apply fix to each part
        print("=" * 60, flush=True)
        print("BEFORE fix_formatting - First part preview:", flush=True)
        if parts:
            print(parts[0][:150], flush=True)
        print("=" * 60, flush=True)
        
        parts = [fix_formatting(p, lang) for p in parts]
        
        print("AFTER fix_formatting - First part preview:", flush=True)
        if parts:
            print(parts[0][:150], flush=True)
        print("=" * 60, flush=True)
        
        # Section header patterns to identify each section
        section_patterns = {
            'vision': [
                '1. vision', '## 1.', '1.', 'vision & objective', 'vision and objective',
                '1. الرؤية', '## 1.', 'الرؤية والأهداف'
            ],
            'gaps': [
                '2. gap', '## 2.', '2.', 'gap analysis',
                '2. تحليل', '## 2.', 'تحليل الفجوات'
            ],
            'pillars': [
                '3. strategic', '## 3.', '3.', 'strategic pillar', 'pillar 1',
                '3. الركائز', '## 3.', 'الركائز الاستراتيجية'
            ],
            'roadmap': [
                '4. implementation', '## 4.', '4.', 'roadmap', 'phase 1 (0-6',
                '4. خارطة', '## 4.', 'خارطة الطريق', 'المرحلة 1'
            ],
            'kpis': [
                '5. key performance', '## 5.', '5.', 'kpi', 'key performance indicator',
                '5. مؤشرات', '## 5.', 'مؤشرات الأداء'
            ],
            'confidence': [
                '6. confidence', '## 6.', '6.', 'confidence assessment', 'confidence score',
                '6. تقييم الثقة', '## 6.', 'تقييم الثقة', 'درجة الثقة'
            ]
        }
        
        def identify_section(text, lang_code):
            """Identify which section type this text belongs to."""
            text_lower = text.lower()[:300]  # Check first 300 chars
            first_line = text.strip().split('\n')[0] if text.strip() else ''
            first_line_lower = first_line.lower()
            
            # MOST RELIABLE: Match "## N." at the start of the first line
            import re as _re
            num_match = _re.match(r'^##\s*(\d)\.', first_line_lower)
            if num_match:
                num = num_match.group(1)
                return {'1': 'vision', '2': 'pillars', '3': 'gaps', '4': 'roadmap', '5': 'kpis', '6': 'confidence'}.get(num)
            
            # SECOND: Match "N. Title" at the start (no ##)
            num_match = _re.match(r'^(\d)\.\s+\w', first_line_lower)
            if num_match:
                num = num_match.group(1)
                return {'1': 'vision', '2': 'pillars', '3': 'gaps', '4': 'roadmap', '5': 'kpis', '6': 'confidence'}.get(num)
            
            # THIRD: Arabic section titles (without numbers)
            if 'الرؤية' in first_line and 'الأهداف' in first_line:
                return 'vision'
            if 'تحليل الفجوات' in first_line or ('الفجوات' in first_line and 'تحليل' in first_line):
                return 'gaps'
            if 'الركائز الاستراتيجية' in first_line or 'الركائز' in first_line:
                return 'pillars'
            if 'خارطة الطريق' in first_line:
                return 'roadmap'
            if 'مؤشرات الأداء' in first_line:
                return 'kpis'
            if 'تقييم الثقة' in first_line or 'درجة الثقة' in first_line or 'تقييم الجاهزية' in first_line:
                return 'confidence'
            
            # FOURTH: English titles (without numbers) — must be in first line only
            if 'vision' in first_line_lower and 'objective' in first_line_lower:
                return 'vision'
            if 'gap analysis' in first_line_lower or ('gap' in first_line_lower and 'analy' in first_line_lower):
                return 'gaps'
            if 'pillar' in first_line_lower or 'strategic pillar' in first_line_lower:
                return 'pillars'
            if 'roadmap' in first_line_lower or 'implementation' in first_line_lower:
                return 'roadmap'
            if 'kpi' in first_line_lower or 'key performance' in first_line_lower:
                return 'kpis'
            if 'confidence' in first_line_lower and ('assessment' in first_line_lower or 'score' in first_line_lower):
                return 'confidence'
            
            # LAST RESORT: Keyword scoring in first 300 chars (weighted)
            keyword_scores = {
                'vision': [('vision statement', 3), ('desired future state', 3), ('strategic objective', 2), ('objective', 1), ('mission', 1), ('الرؤية التنفيذية', 3), ('الأهداف الاستراتيجية', 2)],
                'gaps': [('gap analysis', 3), ('identified gaps', 3), ('current gap', 2), ('gap #', 2), ('الفجوة', 2), ('الفجوات', 2), ('تحليل', 1)],
                'pillars': [('pillar 1', 3), ('pillar 2', 3), ('strategic pillar', 3), ('initiative', 2), ('workstream', 2), ('الركيزة', 3), ('المبادرات', 2), ('الركائز', 3)],
                'roadmap': [('phase 1', 3), ('phase 2', 2), ('roadmap', 3), ('timeline', 2), ('implementation', 1), ('المرحلة', 2), ('خارطة الطريق', 3)],
                'kpis': [('kpi', 3), ('key performance indicator', 3), ('metric', 2), ('target', 1), ('مؤشر', 2), ('مؤشرات الأداء', 3)],
                'confidence': [('confidence score', 3), ('confidence assessment', 3), ('overall confidence', 3), ('الثقة', 2), ('تقييم الثقة', 3), ('درجة الثقة', 3), ('تقييم الجاهزية', 3), ('الجاهزية', 2)]
            }
            
            scores = {}
            for section_type, keywords in keyword_scores.items():
                score = sum(weight for kw, weight in keywords if kw in text_lower)
                scores[section_type] = score
            
            if max(scores.values()) > 0:
                return max(scores, key=scores.get)
            return None
        
        # Initialize sections
        sections = {
            'vision': '',
            'gaps': '',
            'pillars': '',
            'roadmap': '',
            'kpis': '',
            'confidence': ''
        }
        
        def inject_implementation_guidelines(gaps_content, lang_code):
            """Inject implementation guidelines if AI didn't include them or if some are missing."""
            # Extract gaps from the table to create guidelines for each
            import re
            
            # ── CRITICAL: Only scan the identified-gaps table, not workstream rows ──
            # The workstream synthesis section contains numbered activity rows that would
            # also match the gap pattern (| 1 | activity text | ...), generating spurious
            # duplicate implementation guides for every workstream milestone.
            # Truncate the search content at the first "Strategic Workstream Synthesis"
            # or "Workstream 1:" heading so only the real gaps table is scanned.
            _ws_marker = re.search(
                r'(###?\s+Strategic Workstream Synthesis|####\s+Workstream\s+1\s*:|###\s+ورشة العمل|الورشة الأولى)',
                gaps_content
            )
            _search_content = gaps_content[:_ws_marker.start()] if _ws_marker else gaps_content
            
            # Find gap names from table rows (pattern: | number | gap name | description |)
            gap_pattern = r'\|\s*(\d+)\s*\|\s*([^|]+)\s*\|'
            gaps_found = re.findall(gap_pattern, _search_content)
            
            if not gaps_found or len(gaps_found) < 2:  # Need at least 2 (header row doesn't count)
                # ── Fallback: derive gaps_list from existing guide headings ──
                # If the AI omitted the Identified Gaps summary table but DID write
                # implementation guides, extract gap names from those headings so
                # guides can be validated and any missing ones injected.
                if lang_code == 'ar':
                    _guide_hdr_re = re.compile(
                        r'^#{1,4}\s+(?:دليل تنفيذ الفجوة رقم|دليل معالجة الفجوة رقم)\s*(\d+)[:\s]+(.+)$',
                        re.MULTILINE)
                else:
                    _guide_hdr_re = re.compile(
                        r'^#{1,4}\s+Gap\s+#(\d+)\s+Implementation Guide[:\s]+(.+)$',
                        re.MULTILINE)
                _guide_matches = _guide_hdr_re.findall(gaps_content)
                if _guide_matches:
                    # Build a synthetic identified-gaps table from guide headings
                    _synth_rows = ""
                    for _gn, _gname in _guide_matches:
                        _gname = _gname.strip().rstrip(":")
                        _pri = "High"
                        _synth_rows += f"| {_gn} | {_gname} | Identified during organizational assessment | {_pri} | Open - Confirmed |\n"
                    if _synth_rows:
                        # Inject the synthetic table right after the Identified Gaps heading
                        _hdr = ("| # | Gap | Description | Priority | Status |\n"
                                "|---|-----|-------------|----------|--------|\n"
                                if lang_code == 'en' else
                                "| # | الفجوة | الوصف | الأولوية | الحالة |\n"
                                "|---|-------|-------|----------|--------|\n")
                        _tbl_marker = ("### Identified Gaps:" if lang_code == 'en'
                                       else "### الفجوات المحددة:")
                        if _tbl_marker in gaps_content and _hdr.split("\n")[0] not in gaps_content:
                            gaps_content = gaps_content.replace(
                                _tbl_marker,
                                _tbl_marker + "\n" + _hdr + _synth_rows,
                                1
                            )
                        # Re-scan
                        gaps_found = re.findall(gap_pattern, gaps_content[:gaps_content.find(_guide_hdr_re.search(gaps_content).group(0))] if _guide_hdr_re.search(gaps_content) else gaps_content)
                if not gaps_found or len(gaps_found) < 2:
                    return gaps_content
            
            # Skip header row if it contains "Gap" or "الفجوة"
            gaps_list = []
            for num, name in gaps_found:
                name = name.strip()
                if name and name.lower() not in ['gap', 'الفجوة', '#', 'description', 'الوصف', 'priority', 'الأولوية', 'status', 'الحالة']:
                    gaps_list.append((num, name))
            
            if not gaps_list:
                return gaps_content
            
            # ── Guide-count vs table-row consistency check ──────────────────────────
            # The AI sometimes writes only 1-2 rows in the Identified Gaps table but
            # correctly produces 6-8 implementation guide headings. Using only the
            # sparse table rows as valid_gap_nums causes strip_extra_guides to DELETE
            # all the extra guides — exactly backwards from what we want.
            # Fix: if guide headings outnumber table rows, extend gaps_list from guides.
            if lang_code == 'ar':
                _all_guide_re = re.compile(
                    r'^#{1,4}\s+(?:دليل تنفيذ الفجوة رقم|دليل معالجة الفجوة رقم)\s*(\d+)[:\s]+(.+)$',
                    re.MULTILINE)
            else:
                _all_guide_re = re.compile(
                    r'^#{1,4}\s+Gap\s+#(\d+)\s+Implementation Guide[:\s]+(.+)$',
                    re.MULTILINE)
            _all_guides = _all_guide_re.findall(gaps_content)
            _existing_nums = {str(n) for n, _ in gaps_list}
            if len(_all_guides) > len(gaps_list):
                # Guides are more authoritative than the sparse table.
                # Extend gaps_list with any guide whose number is not yet in the table.
                for _gn, _gname in _all_guides:
                    if str(_gn) not in _existing_nums:
                        _gname_clean = _gname.strip().rstrip(':')
                        gaps_list.append((_gn, _gname_clean))
                        _existing_nums.add(str(_gn))
                # Also inject the missing rows into the identified gaps table so it
                # reflects the complete gap set that the document actually covers.
                _tbl_marker2 = ('### Identified Gaps:' if lang_code == 'en'
                                else '### الفجوات المحددة:')
                if _tbl_marker2 in gaps_content:
                    _missing_rows = ''
                    _table_nums = {str(n) for n, _ in gaps_found
                                   if str(n) not in ['gap','#','الفجوة']}
                    for _gn, _gname in sorted(_all_guides, key=lambda x: int(x[0])):
                        if str(_gn) not in _table_nums:
                            _missing_rows += (f'| {_gn} | {_gname.strip().rstrip(":")} '
                                              f'| Identified during assessment | High | Open - Confirmed |\n')
                    if _missing_rows:
                        # Inject missing rows INSIDE the existing table block.
                        # Strategy: find the last pipe-containing line before the
                        # workstream synthesis heading, then append right after it.
                        # This keeps all rows in the same table (continuous pipe block).
                        _ws_pos2 = re.search(
                            r'(###?\s+Strategic Workstream|####\s+Workstream\s*1)',
                            gaps_content)
                        if _ws_pos2:
                            _search_region = gaps_content[:_ws_pos2.start()]
                            # Find the last table row (ends with '|') in the search region
                            _last_pipe_m = list(re.finditer(r'^\|[^\n]+\|\s*$', _search_region, re.MULTILINE))
                            if _last_pipe_m:
                                _insert_at = _last_pipe_m[-1].end()
                                gaps_content = (gaps_content[:_insert_at]
                                                + '\n' + _missing_rows.rstrip('\n')
                                                + gaps_content[_insert_at:])
                            else:
                                # Fallback: insert before workstream heading
                                _insert_at = _ws_pos2.start()
                                gaps_content = (gaps_content[:_insert_at]
                                                + _missing_rows + '\n'
                                                + gaps_content[_insert_at:])

            # ── CRITICAL: Remove implementation guides for gap numbers NOT in gaps_list ──
            # The AI often generates more guides than there are identified gaps.
            # We keep only guides whose number appears in the identified gaps table.
            valid_gap_nums = {str(num) for num, _ in gaps_list}
            
            def strip_extra_guides(content, valid_nums, is_arabic):
                """Remove guide blocks whose gap number is not in valid_nums."""
                if is_arabic:
                    # Match: ### دليل تنفيذ الفجوة رقم N: ... or ### دليل معالجة الفجوة رقم N: ...
                    heading_pattern = re.compile(
                        r'(^#{1,4}\s+(?:دليل تنفيذ الفجوة رقم|دليل معالجة الفجوة رقم)\s*(\d+)[^\n]*$)',
                        re.MULTILINE
                    )
                else:
                    # Match: ### Gap #N Implementation Guide: ...
                    heading_pattern = re.compile(
                        r'(^#{1,4}\s+Gap\s+#(\d+)\s+Implementation Guide[^\n]*$)',
                        re.MULTILINE
                    )
                
                matches = list(heading_pattern.finditer(content))
                if not matches:
                    return content
                
                # Check if any guides exist outside valid_nums
                invalid_found = any(m.group(2) not in valid_nums for m in matches)
                if not invalid_found:
                    return content  # All guides are valid — nothing to strip
                
                # Build new content by keeping only valid guide blocks
                # A guide block runs from its heading to the next guide heading (or end of content)
                result_parts = []
                # Content before the first guide heading
                result_parts.append(content[:matches[0].start()])
                
                for i, m in enumerate(matches):
                    gap_num = m.group(2)
                    block_start = m.start()
                    block_end = matches[i + 1].start() if i + 1 < len(matches) else len(content)
                    
                    if gap_num in valid_nums:
                        result_parts.append(content[block_start:block_end])
                    # else: skip this guide block entirely
                
                return ''.join(result_parts)
            
            gaps_content = strip_extra_guides(gaps_content, valid_gap_nums, lang_code == 'ar')
            
