@app.route('/api/test-docx', methods=['GET'])
@login_required
def api_test_docx():
    """Test if DOCX generation works at all on this server."""
    try:
        from io import BytesIO
        from docx import Document
        from docx.shared import Inches
        doc = Document()
        doc.add_heading('Test Document', 0)
        doc.add_paragraph('This is a test paragraph.')
        table = doc.add_table(rows=2, cols=2)
        table.rows[0].cells[0].text = 'Test'
        table.rows[0].cells[1].text = 'Table'
        table.rows[1].cells[0].text = '1'
        table.rows[1].cells[1].text = '2'
        buffer = BytesIO()
        doc.save(buffer)
        buffer.seek(0)
        from flask import send_file
        return send_file(buffer, mimetype='application/vnd.openxmlformats-officedocument.wordprocessingml.document',
                        as_attachment=True, download_name='test.docx')
    except Exception as e:
        import traceback
        traceback.print_exc()
        return jsonify({'error': str(e), 'trace': traceback.format_exc()}), 500

# ── Async DOCX export store ────────────────────────────────────────────────────
# Keyed by task_id → {'status': 'pending'|'done'|'error', 'tmp': path, 'filename': ...}
# Background thread writes here; polling/download endpoints read it.
# /tmp is shared across Gunicorn workers on the same Render instance.
_export_store: dict = {}


@app.route('/api/generate-pdf-async', methods=['POST'])
@login_required
def api_generate_pdf_async():
    """Start PDF generation in a background thread; return task_id immediately.
    Avoids Render's 30-second inactivity proxy timeout."""
    import uuid, threading, tempfile

    try:
        data = request.get_json(force=True) or {}
    except Exception:
        return jsonify({'error': 'Invalid JSON'}), 400

    content  = data.get('content', '').strip()
    filename = data.get('filename', 'document')
    lang     = data.get('language', 'en')
    org_name = data.get('org_name', '').strip()
    sector   = data.get('sector', '').strip()
    doc_type = data.get('doc_type', 'Strategy Document')
    domain   = data.get('domain', '')

    if not content:
        return jsonify({'error': 'No content'}), 400

    task_id = str(uuid.uuid4())
    _export_store[task_id] = {'status': 'pending', 'filename': filename}

    _content  = content
    _filename = filename
    _lang     = lang
    _org_name = org_name
    _sector   = sector
    _doc_type = doc_type
    _domain   = domain
    _task_id  = task_id

    def _build_pdf():
        import tempfile
        try:
            print(f"ASYNC PDF: starting build for task {_task_id[:8]}", flush=True)
            # Call the sync PDF endpoint logic via a sub-request to the existing endpoint
            # We replicate the same logic used in api_generate_pdf but store result to /tmp
            from io import BytesIO
            # Import all PDF deps
            from reportlab.lib.pagesizes import A4
            from reportlab.platypus import SimpleDocTemplate
            buffer = BytesIO()
            # Use the existing sync route via a fake request to reuse all logic
            with app.test_request_context(
                '/api/generate-pdf',
                method='POST',
                json={'content': _content, 'filename': _filename, 'language': _lang,
                      'org_name': _org_name, 'sector': _sector, 'doc_type': _doc_type, 'domain': _domain},
                headers={'Content-Type': 'application/json'}
            ):
                # Manually patch session for auth
                from flask import session as _sess
                _sess['user_id'] = 1  # background task — auth already validated upstream
                resp = api_generate_pdf()

            # api_generate_pdf() may return a tuple (Response, status_code) on error,
            # or a plain Response (send_file) on success. Handle both cases.
            if isinstance(resp, tuple):
                # Error response: (jsonify({...}), 500)
                _resp_obj, _status_code = resp[0], resp[1]
                try:
                    err_body = _resp_obj.get_data(as_text=True)
                except Exception:
                    err_body = str(_resp_obj)
                raise ValueError(f"PDF generation failed (HTTP {_status_code}): {err_body[:300]}")

            # Success: resp is a Flask Response from send_file() with direct_passthrough=True.
            # resp.status_code check as safety net for non-200 plain responses.
            if hasattr(resp, 'status_code') and resp.status_code != 200:
                try:
                    err_body = resp.get_data(as_text=True)
                except Exception:
                    err_body = str(resp)
                raise ValueError(f"PDF generation failed (HTTP {resp.status_code}): {err_body[:300]}")

            # Read bytes from the send_file() response using the response iterator.
            raw = b''
            try:
                raw = b''.join(resp.response)
            except Exception as iter_err:
                print(f"ASYNC PDF: iterator failed ({iter_err}), trying get_data", flush=True)
                if hasattr(resp, 'get_data'):
                    try:
                        raw = resp.get_data(as_text=False)
                    except Exception:
                        pass

            if not raw or len(raw) < 100:
                raise ValueError(f"PDF generation returned empty/invalid content (got {len(raw)} bytes)")

            tmp = tempfile.NamedTemporaryFile(
                suffix='.pdf', delete=False,
                prefix=f'mizan_export_{_task_id}_'
            )
            tmp.write(raw)
            tmp.close()
            _export_store[_task_id] = {
                'status': 'done', 'tmp': tmp.name, 'filename': _filename, 'fmt': 'pdf'
            }
            print(f"ASYNC PDF: task {_task_id[:8]} done ({len(raw):,} bytes)", flush=True)
        except Exception as exc:
            import traceback
            print(f"ASYNC PDF ERROR task {_task_id[:8]}: {exc}\n{traceback.format_exc()}", flush=True)
            _export_store[_task_id] = {'status': 'error', 'error': str(exc)}

    threading.Thread(target=_build_pdf, daemon=True).start()
    return jsonify({'task_id': task_id})

@app.route('/api/generate-docx-async', methods=['POST'])
@login_required
def api_generate_docx_async():
    """Start DOCX generation in a background thread; return task_id immediately.
    Avoids Render's 30-second inactivity proxy timeout.
    Uses app.test_client() so Flask session/auth works without HTTP overhead."""
    import uuid, threading

    try:
        data = request.get_json(force=True) or {}
    except Exception:
        return jsonify({'error': 'Invalid JSON'}), 400

    content  = data.get('content', '').strip()
    filename = data.get('filename', 'document')
    lang     = data.get('language', 'en')
    org_name = data.get('org_name', '').strip()
    sector   = data.get('sector', '').strip()
    doc_type = data.get('doc_type', 'Strategy Document')
    domain   = data.get('domain', '')

    if not content:
        return jsonify({'error': 'No content'}), 400

    task_id = str(uuid.uuid4())

    _export_store[task_id] = {'status': 'pending', 'filename': filename}

    _content  = content
    _filename = filename
    _lang     = lang
    _org_name = org_name
    _sector   = sector
    _doc_type = doc_type
    _domain   = domain
    _task_id  = task_id

    def _build():
        import tempfile
        try:
            print(f"ASYNC DOCX: starting build for task {_task_id[:8]}", flush=True)
            # Call the extracted build function directly — no Flask routing, no auth needed
            raw = _build_docx_bytes(_content, _filename, _lang, _org_name, _sector, _doc_type, _domain)
            tmp = tempfile.NamedTemporaryFile(
                suffix='.docx', delete=False,
                prefix=f'mizan_export_{_task_id}_'
            )
            tmp.write(raw)
            tmp.close()
            _export_store[_task_id] = {
                'status': 'done', 'tmp': tmp.name, 'filename': _filename
            }
            print(f"ASYNC DOCX: task {_task_id[:8]} done ({len(raw):,} bytes)", flush=True)
        except Exception as exc:
            import traceback
            print(f"ASYNC DOCX ERROR task {_task_id[:8]}: {exc}\n{traceback.format_exc()}", flush=True)
            _export_store[_task_id] = {'status': 'error', 'error': str(exc)}

    threading.Thread(target=_build, daemon=True).start()
    return jsonify({'task_id': task_id})


@app.route('/api/export-status/<task_id>')
@login_required
def api_export_status(task_id):
    """Poll async export task status."""
    entry = _export_store.get(task_id)
    if not entry:
        # Also check other workers via a temp-file sentinel
        import os
        candidates = [f for f in os.listdir('/tmp') if f.startswith(f'mizan_export_{task_id}')]
        if candidates:
            return jsonify({'status': 'done', 'task_id': task_id})
        return jsonify({'status': 'not_found'}), 404

    status = entry.get('status', 'pending')
    if status == 'done':
        return jsonify({'status': 'done', 'task_id': task_id})
    elif status == 'error':
        return jsonify({'status': 'error', 'error': entry.get('error', 'Unknown error')}), 500
    return jsonify({'status': 'pending'})


@app.route('/api/export-download/<task_id>')
@login_required
def api_export_download(task_id):
    """Download completed async export file."""
    import os
    from flask import send_file as _send_file

    entry = _export_store.get(task_id, {})
    tmp_path = entry.get('tmp')
    filename = entry.get('filename', 'document')

    # Cross-worker fallback: scan /tmp
    if not tmp_path:
        candidates = [f'/tmp/{f}' for f in os.listdir('/tmp')
                      if f.startswith('mizan_export_') and task_id in f
                      and (f.endswith('.docx') or f.endswith('.pdf'))]
        if candidates:
            tmp_path = candidates[0]
            filename = entry.get('filename', 'document')

    if not tmp_path or not os.path.exists(tmp_path):
        return jsonify({'error': 'File not ready or already downloaded'}), 404

    # Determine format from stored entry or file extension
    fmt = entry.get('fmt', 'docx')
    if not fmt and tmp_path:
        fmt = 'pdf' if tmp_path.endswith('.pdf') else 'docx'

    safe_name = filename.replace('"', '').replace('\n', '').replace('\r', '')
    if fmt == 'pdf':
        mime = 'application/pdf'
        dl_name = f'{safe_name}.pdf'
    else:
        mime = 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        dl_name = f'{safe_name}.docx'

    try:
        response = _send_file(
            tmp_path,
            mimetype=mime,
            as_attachment=True,
            download_name=dl_name
        )
        # Clean up after sending
        @response.call_on_close
        def _cleanup():
            try:
                os.unlink(tmp_path)
            except Exception:
                pass
        return response
    except Exception as e:
        return jsonify({'error': str(e)}), 500


def _build_docx_bytes(content, filename, lang, org_name='', sector='', doc_type='Strategy Document', domain=''):
    """Build a DOCX and return raw bytes. Called by both the sync route and async thread."""
    from io import BytesIO
    import re
    from docx import Document
    from docx.shared import Inches, Pt, Cm, RGBColor
    from docx.enum.text import WD_ALIGN_PARAGRAPH
    from docx.enum.table import WD_TABLE_ALIGNMENT
    from docx.oxml.ns import nsdecls, qn
    from docx.oxml import parse_xml

    # Preprocessing (same as before)
    import re as re_docx

    is_arabic = lang == 'ar'
    doc = Document()
    
    # ═══ BIG4 DOCUMENT STYLING ═══
    style = doc.styles['Normal']
    style.font.name = 'Calibri'
    style.font.size = Pt(11)
    style.font.color.rgb = RGBColor(0x33, 0x33, 0x33)
    style.paragraph_format.space_after = Pt(6)
    style.paragraph_format.line_spacing = 1.15
    
    BIG4_NAVY = RGBColor(0x1B, 0x2A, 0x4A)
    BIG4_ACCENT = RGBColor(0x2E, 0x75, 0xB6)
    BIG4_TABLE_HEADER = '1B2A4A'
    BIG4_TABLE_ALT = 'F2F6FA'
    
    for hs, sz, clr in [('Heading 1', 18, BIG4_NAVY), ('Heading 2', 14, BIG4_ACCENT), ('Heading 3', 12, BIG4_NAVY)]:
        try:
            hs_style = doc.styles[hs]
            hs_style.font.name = 'Calibri'
            hs_style.font.size = Pt(sz)
            hs_style.font.bold = True
            hs_style.font.color.rgb = clr
            hs_style.paragraph_format.space_before = Pt(18 if sz > 12 else 12)
            hs_style.paragraph_format.space_after = Pt(8 if sz > 12 else 6)
            hs_style.paragraph_format.keep_with_next = True
        except Exception:
            pass
    try:
        ts = doc.styles['Title']
        ts.font.name = 'Calibri'
        ts.font.size = Pt(26)
        ts.font.bold = True
        ts.font.color.rgb = BIG4_NAVY
        ts.paragraph_format.space_after = Pt(4)
    except Exception:
        pass
    
    # Page size, margins, and page numbers
    for section in doc.sections:
        section.page_width = Inches(8.5)
        section.page_height = Inches(11)
        section.top_margin = Inches(1.0)
        section.bottom_margin = Inches(0.75)
        section.left_margin = Inches(1.0)
        section.right_margin = Inches(1.0)
    try:
        footer = doc.sections[0].footer
        footer.is_linked_to_previous = False
        fp = footer.paragraphs[0] if footer.paragraphs else footer.add_paragraph()
        fp.alignment = WD_ALIGN_PARAGRAPH.CENTER
        run1 = fp.add_run()
        run1.font.size = Pt(9)
        run1.font.color.rgb = RGBColor(0x99, 0x99, 0x99)
        run1._r.append(parse_xml(f'<w:fldChar {nsdecls("w")} w:fldCharType="begin"/>'))
        run2 = fp.add_run()
        run2.font.size = Pt(9)
        run2._r.append(parse_xml(f'<w:instrText {nsdecls("w")} xml:space="preserve"> PAGE </w:instrText>'))
        run3 = fp.add_run()
        run3.font.size = Pt(9)
        run3._r.append(parse_xml(f'<w:fldChar {nsdecls("w")} w:fldCharType="end"/>'))
        pPr = fp._p.get_or_add_pPr()
        pPr.append(parse_xml(f'<w:pBdr {nsdecls("w")}><w:top w:val="single" w:sz="4" w:space="4" w:color="CCCCCC"/></w:pBdr>'))
    except Exception as footer_err:
        print(f"Footer (non-fatal): {footer_err}", flush=True)
    
    # Set document-level RTL for Arabic
    if is_arabic:
        try:
            body = doc.element.body
            sectPr = body.find(qn('w:sectPr'))
            if sectPr is not None:
                bidi = parse_xml(f'<w:bidi {nsdecls("w")} w:val="1"/>')
                sectPr.append(bidi)
        except Exception:
            pass  # Non-critical
    
    def set_rtl_paragraph(paragraph):
        """Set full RTL properties on a paragraph."""
        if not is_arabic:
            return
        paragraph.alignment = WD_ALIGN_PARAGRAPH.RIGHT
        # Set paragraph-level RTL
        pPr = paragraph._p.get_or_add_pPr()
        bidi = parse_xml(f'<w:bidi {nsdecls("w")} w:val="1"/>')
        pPr.append(bidi)
        # Set RTL on each run
        for run in paragraph.runs:
            rPr = run._r.get_or_add_rPr()
            rtl_elem = parse_xml(f'<w:rtl {nsdecls("w")} w:val="1"/>')
            rPr.append(rtl_elem)
    
    def set_rtl_run(run):
        """Set RTL on a single run."""
        if not is_arabic:
            return
        rPr = run._r.get_or_add_rPr()
        rtl_elem = parse_xml(f'<w:rtl {nsdecls("w")} w:val="1"/>')
        rPr.append(rtl_elem)
    
    def add_rtl_heading(text, level):
        """Add a heading with proper RTL and inline bold support."""
        # Strip ** markers from heading text but keep the text
        clean_text = re.sub(r'\*\*(.+?)\*\*', r'\1', text)
        h = doc.add_heading('', level=level)
        
        # Process inline bold within heading
        if '**' in text:
            parts = re.split(r'\*\*(.+?)\*\*', text)
            for idx_part, part in enumerate(parts):
                if part:
                    run = h.add_run(part)
                    if idx_part % 2 == 1:
                        run.bold = True
                    if is_arabic:
                        set_rtl_run(run)
        else:
            run = h.add_run(clean_text)
            if is_arabic:
                set_rtl_run(run)
        
        if is_arabic:
            set_rtl_paragraph(h)
        return h
    
    def add_formatted_paragraph(text, base_bold=False):
        """Add a paragraph with inline bold/formatting support."""
        p = doc.add_paragraph()
        if '**' in text:
            parts = re.split(r'\*\*(.+?)\*\*', text)
            for idx_part, part in enumerate(parts):
                if part:
                    run = p.add_run(part)
                    run.bold = (idx_part % 2 == 1) or base_bold
                    if is_arabic:
                        set_rtl_run(run)
        else:
            run = p.add_run(text)
            if base_bold:
                run.bold = True
            if is_arabic:
                set_rtl_run(run)
        if is_arabic:
            set_rtl_paragraph(p)
        # Callout label spacing: bold-only paragraphs (Strategic Mandate, etc.)
        # need breathing room so they don't visually merge with surrounding prose.
        if base_bold:
            p.paragraph_format.space_before = Pt(12)
            p.paragraph_format.space_after  = Pt(4)
        return p
    
    def add_rtl_paragraph(text, bold=False):
        """Add a normal paragraph with proper RTL."""
        if '**' in text:
            return add_formatted_paragraph(text, base_bold=bold)
        p = doc.add_paragraph()
        run = p.add_run(text)
        if bold:
            run.bold = True
            # Callout label spacing — same rule as add_formatted_paragraph
            p.paragraph_format.space_before = Pt(12)
            p.paragraph_format.space_after  = Pt(4)
        if is_arabic:
            set_rtl_paragraph(p)
        return p
    
    # ---- Table helpers ----
    
    def parse_markdown_table(lines, start_idx):
        """Parse markdown table starting at start_idx.
        Also merges adjacent table fragments (same column count, separated by blank lines)."""
        table_rows = []
        idx = start_idx
        expected_cols = 0
        
        while idx < len(lines):
            ln = lines[idx].strip()
            if ln.startswith('|') and ln.endswith('|'):
                if '---' in ln or ':-' in ln or '-:' in ln:
                    idx += 1
                    continue
                cells = [cell.strip() for cell in ln.split('|')[1:-1]]
                if cells:
                    # Skip ALL phantom placeholder rows injected by _inject_table_headers.
                    # Covers all column counts of the default-header-map patterns.
                    _pl = [c.lower() for c in cells]
                    _phantom_rows = [
                        ['#', 'item', 'detail 1', 'detail 2', 'detail 3', 'status'],
                        ['#', 'item', 'details', 'notes', 'status'],
                        ['#', 'item', 'details', 'notes'],
                        ['#', 'item', 'description', 'notes'],
                        ['#', 'item', 'details'],
                        ['item', 'description', 'details', 'notes'],
                        ['item', 'details', 'notes', 'status', 'priority'],
                    ]
                    if _pl in _phantom_rows:
                        idx += 1
                        continue
                    if expected_cols == 0:
                        expected_cols = len(cells)
                    table_rows.append(cells)
                idx += 1
            elif not ln:
                # Blank line — peek ahead for continuation of same table
                peek = idx + 1
                while peek < len(lines) and not lines[peek].strip():
                    peek += 1
                if peek < len(lines):
                    peek_ln = lines[peek].strip()
                    if peek_ln.startswith('|') and peek_ln.endswith('|'):
                        # Check if it's a new table header (followed by separator)
                        peek_cells = [c.strip() for c in peek_ln.split('|')[1:-1]]
                        peek_next = lines[peek + 1].strip() if peek + 1 < len(lines) else ''
                        is_separator = peek_next.startswith('|') and '---' in peek_next
                        
                        if is_separator and expected_cols > 0 and len(peek_cells) == expected_cols:
                            # Same-width table fragment — merge (skip duplicate header + separator)
                            idx = peek + 2  # Skip header + separator
                            continue
                        elif not is_separator and expected_cols > 0:
                            # Data row continuation after blank line — merge
                            idx = peek
                            continue
                # Not a continuation — end table
                break
            else:
                break
        return table_rows, idx
    
    def add_table_to_doc(doc, table_data, lang):
        """Add a formatted table with RTL support and professional styling."""
        if not table_data or len(table_data) < 1:
            return
        
        # Normalize all rows to same column count (prevent crash)
        num_cols = max(len(row) for row in table_data)
        for row in table_data:
            while len(row) < num_cols:
                row.append('')
        
        table = doc.add_table(rows=len(table_data), cols=num_cols)
        try:
            table.style = 'Table Grid'
        except Exception:
            pass
        
        # Auto-fit table to window width
        try:
            tbl = table._tbl
            tblPr = tbl.tblPr if tbl.tblPr is not None else parse_xml(f'<w:tblPr {nsdecls("w")}/>')
            # Set table width to 100% of available text area
            # Remove any existing tblW to avoid duplicates
            for existing_w in tblPr.findall('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}tblW'):
                tblPr.remove(existing_w)
            tblW = parse_xml(f'<w:tblW {nsdecls("w")} w:type="pct" w:w="5000"/>')
            tblPr.append(tblW)
            
            # Force fixed table layout — prevents column overflow in Word
            for existing_layout in tblPr.findall('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}tblLayout'):
                tblPr.remove(existing_layout)
            tblLayout = parse_xml(f'<w:tblLayout {nsdecls("w")} w:type="fixed"/>')
            tblPr.append(tblLayout)
            
            # Refined thin borders — professional Big 4 style
            tblBorders = parse_xml(
                f'<w:tblBorders {nsdecls("w")}>'
                f'<w:top w:val="single" w:sz="4" w:space="0" w:color="1B2A4A"/>'
                f'<w:left w:val="single" w:sz="4" w:space="0" w:color="D0D5DD"/>'
                f'<w:bottom w:val="single" w:sz="6" w:space="0" w:color="1B2A4A"/>'
                f'<w:right w:val="single" w:sz="4" w:space="0" w:color="D0D5DD"/>'
                f'<w:insideH w:val="single" w:sz="4" w:space="0" w:color="E2E8F0"/>'
                f'<w:insideV w:val="single" w:sz="4" w:space="0" w:color="E2E8F0"/>'
                f'</w:tblBorders>'
            )
            tblPr.append(tblBorders)
            
            # Set table RTL direction for Arabic
            if is_arabic:
                bidi_visual = parse_xml(f'<w:bidiVisual {nsdecls("w")} w:val="1"/>')
                tblPr.append(bidi_visual)
        except Exception:
            pass
        
        # --- Set proportional column widths ---
        try:
            from docx.oxml.ns import qn
            from docx.shared import Twips
            # Page width ~9360 twips (A4 with 1.5cm margins each side)
            page_twips = 9360
            header_row_lower = [str(c).lower().strip('*# ') for c in table_data[0]] if table_data else []
            
            def _col_weight(h):
                narrow = {'#','م','no','no.','الرقم','رقم','status','الحالة','priority','الأولوية',
                          'likelihood','الاحتمالية','impact','التأثير','level','المستوى',
                          'timeframe','الإطار الزمني','timeline','الجدول الزمني','score','النتيجة',
                          'step','الخطوة','خطوة',
                          'tool/system','النظام/الأداة','الأداة'}
                # RACI role columns — content is multi-word role names like "Executive Management"
                # Must be MEDIUM (weight 1.6) not narrow (0.8) to get enough column width
                medium = {'owner','المسؤول','مسؤول',
                          'responsible','accountable','consulted','informed',
                          'المسؤول التنفيذي','المحاسب','المستشار','المطلع'}
                wide   = {'description','الوصف','justification','المبرر','recommendation','التوصية',
                          'mitigation plan','خطة التخفيف','deliverable','المخرج','المخرجات',
                          'objective','الهدف','initiative','المبادرة','action','الإجراء',
                          'gap','الفجوة','observation','الملاحظة','factor','العامل',
                          'activity','النشاط','control','الضابط','threat analysis','تحليل التهديد',
                          'calculation formula','صيغة الاحتساب','formula','data source','مصدر البيانات',
                          'short-term goals','immediate actions','الإجراءات الفورية','أهداف المدى القصير',
                          'output','المخرج','key deliverable','المخرج الرئيسي'}
                if any(k in h for k in medium):
                    return 1.6
                if any(k in h for k in narrow) or len(h) <= 2:
                    return 0.8
                if any(k in h for k in wide):
                    return 3.0
                return 1.6  # medium

            weights = [_col_weight(h) for h in header_row_lower]

            # DOCX FIX-B: If col-0 header is '#' but data rows have prose
            # in col-0 (synthesis stripped row numbers), bump col-0 weight
            # to WIDE so it gets proper column space instead of ~8% of page.
            import re as _re_docx
            if (header_row_lower and
                    header_row_lower[0].strip() in ('#', 'م', 'no', 'no.')):
                _d0_vals = [str(r[0]).strip() for r in table_data[1:] if r]
                _d0_long = sum(1 for t in _d0_vals
                               if not _re_docx.match(r'^\s*\d{0,3}\s*$', t)
                               and len(t) > 12)
                if _d0_vals and _d0_long > len(_d0_vals) * 0.4:
                    weights[0] = 3.0   # treat col-0 as wide content column

            total_w = sum(weights) or 1
            col_twips = [int((w / total_w) * page_twips) for w in weights]
            
            # Apply to each column via tblGrid
            tbl = table._tbl
            tblGrid = tbl.find(qn('w:tblGrid'))
            if tblGrid is None:
                tblGrid = parse_xml(f'<w:tblGrid {nsdecls("w")}/>')
                tbl.insert(0, tblGrid)
            # Clear existing gridCols and set new ones
            for gc in tblGrid.findall(qn('w:gridCol')):
                tblGrid.remove(gc)
            for tw in col_twips:
                gc = parse_xml(f'<w:gridCol {nsdecls("w")} w:w="{tw}"/>')
                tblGrid.append(gc)
            # Also set each cell width
            for i_row, row_obj in enumerate(table.rows):
                for j_col, cell_obj in enumerate(row_obj.cells):
                    tw = col_twips[j_col] if j_col < len(col_twips) else (page_twips // num_cols)
                    tc = cell_obj._tc
                    tcPr = tc.get_or_add_tcPr()
                    tcW = tcPr.find(qn('w:tcW'))
                    if tcW is None:
                        tcW = parse_xml(f'<w:tcW {nsdecls("w")} w:type="dxa" w:w="{tw}"/>')
                        tcPr.append(tcW)
                    else:
                        tcW.set(qn('w:w'), str(tw))
                        tcW.set(qn('w:type'), 'dxa')
        except Exception as cw_err:
            pass
        
        for i, row_data in enumerate(table_data):
            row = table.rows[i]
            for j, cell_text in enumerate(row_data):
                if j < len(row.cells):
                    cell = row.cells[j]
                    # Clear default paragraph and add formatted text
                    cell.text = ''
                    p = cell.paragraphs[0] if cell.paragraphs else cell.add_paragraph()
                    p.paragraph_format.space_before = Pt(2)
                    p.paragraph_format.space_after = Pt(2)
                    p.paragraph_format.line_spacing = 1.0
                    
                    # Process inline bold within cells
                    if '**' in cell_text:
                        parts = re.split(r'\*\*(.+?)\*\*', cell_text)
                        for idx_part, part in enumerate(parts):
                            if part:
                                run = p.add_run(part)
                                run.bold = (idx_part % 2 == 1) or (i == 0)
                                run.font.name = 'Calibri'
                                run.font.size = Pt(9) if i > 0 else Pt(9.5)
                                if is_arabic:
                                    set_rtl_run(run)
                    else:
                        run = p.add_run(cell_text)
                        run.font.name = 'Calibri'
                        run.font.size = Pt(9) if i > 0 else Pt(9.5)
                        if i == 0:
                            run.bold = True
                        if is_arabic:
                            set_rtl_run(run)
                    
                    # Style header row with Big4 navy
                    if i == 0:
                        for paragraph in cell.paragraphs:
                            for r in paragraph.runs:
                                r.bold = True
                                r.font.color.rgb = RGBColor(0xFF, 0xFF, 0xFF)
                        shading = parse_xml(f'<w:shd {nsdecls("w")} w:fill="{BIG4_TABLE_HEADER}"/>')
                        cell._tc.get_or_add_tcPr().append(shading)
                    else:
                        # Alternate row shading
                        if i % 2 == 0:
                            shading = parse_xml(f'<w:shd {nsdecls("w")} w:fill="{BIG4_TABLE_ALT}"/>')
                            cell._tc.get_or_add_tcPr().append(shading)
                    
                    # Set cell padding
                    try:
                        tc = cell._tc
                        tcPr = tc.get_or_add_tcPr()
                        tcMar = parse_xml(
                            f'<w:tcMar {nsdecls("w")}>'
                            f'<w:top w:w="50" w:type="dxa"/>'
                            f'<w:start w:w="100" w:type="dxa"/>'
                            f'<w:bottom w:w="50" w:type="dxa"/>'
                            f'<w:end w:w="100" w:type="dxa"/>'
                            f'</w:tcMar>'
                        )
                        tcPr.append(tcMar)
                        # Vertical alignment
                        vAlign = parse_xml(f'<w:vAlign {nsdecls("w")} w:val="center"/>' if i == 0 else f'<w:vAlign {nsdecls("w")} w:val="top"/>')
                        tcPr.append(vAlign)
                    except Exception:
                        pass
                    
                    # Set RTL/alignment on each cell paragraph
                    for paragraph in cell.paragraphs:
                        if is_arabic:
                            set_rtl_paragraph(paragraph)
                        else:
                            paragraph.alignment = WD_ALIGN_PARAGRAPH.LEFT
        
        # Add spacing after table
        doc.add_paragraph()
    
    # ── DOCX Cover Page ─────────────────────────────────────────────────────
    import datetime as _dt_docx
    from docx.oxml import parse_xml
    from docx.oxml.ns import nsdecls
    try:
        _today_docx = _dt_docx.date.today().strftime('%d %B %Y')
        _org_display = org_name.strip() if org_name and org_name.strip() else 'The Organization'
        _sector_display = sector.strip() if sector and sector.strip() else '—'
        _doc_type_display = doc_type if doc_type else ('وثيقة استراتيجية' if is_arabic else 'Strategy Document')
        _domain_display = filename.replace("_", " ").title()

        # ── Top navy bar: org name ────────────────────────────────────────
        bar_p = doc.add_paragraph()
        bar_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
        bar_run = bar_p.add_run(_org_display)
        bar_run.bold = True
        bar_run.font.name = 'Calibri'
        bar_run.font.size = Pt(13)
        bar_run.font.color.rgb = RGBColor(0xFF, 0xFF, 0xFF)
        pPr = bar_p._p.get_or_add_pPr()
        pBdr = parse_xml(
            f'<w:pBdr {nsdecls("w")}>'
            f'<w:top w:val="single" w:sz="0" w:space="0" w:color="1B2A4A"/>'
            f'<w:bottom w:val="single" w:sz="0" w:space="0" w:color="1B2A4A"/>'
            f'</w:pBdr>'
        )
        pPr.append(pBdr)
        shd = parse_xml(f'<w:shd {nsdecls("w")} w:val="clear" w:color="auto" w:fill="1B2A4A"/>')
        pPr.append(shd)
        bar_p.paragraph_format.space_before = Pt(0)
        bar_p.paragraph_format.space_after  = Pt(0)
        bar_p.paragraph_format.left_indent  = Inches(-1.0)
        bar_p.paragraph_format.right_indent = Inches(-1.0)

        doc.add_paragraph()  # spacer

        # ── Logo (if available) ───────────────────────────────────────────
        try:
            user_logo = None
            if session.get('user_id'):
                user_row = get_db().execute('SELECT logo_path FROM users WHERE id = ?', (session['user_id'],)).fetchone()
                if user_row and user_row['logo_path'] and os.path.isfile(user_row['logo_path']):
                    user_logo = user_row['logo_path']
            if user_logo:
                logo_para = doc.add_paragraph()
                logo_para.alignment = WD_ALIGN_PARAGRAPH.LEFT
                logo_para.add_run().add_picture(user_logo, width=Inches(1.6))
                doc.add_paragraph()
        except Exception:
            pass

        # ── Document type (large title) ───────────────────────────────────
        title_p = doc.add_paragraph()
        title_p.alignment = WD_ALIGN_PARAGRAPH.LEFT if not is_arabic else WD_ALIGN_PARAGRAPH.RIGHT
        title_run = title_p.add_run(_doc_type_display)
        title_run.bold = True
        title_run.font.name = 'Calibri'
        title_run.font.size = Pt(28)
        title_run.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
        title_p.paragraph_format.space_before = Pt(18)
        title_p.paragraph_format.space_after  = Pt(4)

        # ── Domain subtitle ───────────────────────────────────────────────
        sub_p = doc.add_paragraph()
        sub_p.alignment = WD_ALIGN_PARAGRAPH.LEFT if not is_arabic else WD_ALIGN_PARAGRAPH.RIGHT
        sub_run = sub_p.add_run(_domain_display)
        sub_run.font.name = 'Calibri'
        sub_run.font.size = Pt(13)
        sub_run.font.color.rgb = RGBColor(0x44, 0x54, 0x63)
        sub_p.paragraph_format.space_after = Pt(6)

        # ── Gold divider rule ─────────────────────────────────────────────
        rule_p = doc.add_paragraph()
        rule_pPr = rule_p._p.get_or_add_pPr()
        rule_pBdr = parse_xml(
            f'<w:pBdr {nsdecls("w")}>'
            f'<w:bottom w:val="single" w:sz="18" w:space="1" w:color="C9A84C"/>'
            f'</w:pBdr>'
        )
        rule_pPr.append(rule_pBdr)
        rule_p.paragraph_format.space_after = Pt(12)

        # ── Metadata info box (light grey table) ──────────────────────────
        if is_arabic:
            _meta_rows = [
                ['نوع الوثيقة', _doc_type_display],
                ['القطاع',       _sector_display],
                ['التصنيف',      'سري'],
                ['الإصدار',      '1.0'],
                ['الحالة',       'مسودة'],
                ['تاريخ الإعداد', _today_docx],
                ['أُعدّ بواسطة', 'منصة ميزان GRC'],
            ]
        else:
            _meta_rows = [
                ['Document Type',  _doc_type_display],
                ['Sector',         _sector_display],
                ['Classification', 'Confidential'],
                ['Version',        '1.0'],
                ['Status',         'Draft'],
                ['Prepared',       _today_docx],
                ['Prepared by',    'Mizan GRC Platform'],
            ]

        meta_tbl = doc.add_table(rows=len(_meta_rows), cols=2)
        meta_tbl.style = 'Table Grid'
        # Full-width
        try:
            tbl_el = meta_tbl._tbl
            tPr = tbl_el.tblPr if tbl_el.tblPr is not None else parse_xml(f'<w:tblPr {nsdecls("w")}/>')
            for _ex in tPr.findall('{http://schemas.openxmlformats.org/wordprocessingml/2006/main}tblW'):
                tPr.remove(_ex)
            tPr.append(parse_xml(f'<w:tblW {nsdecls("w")} w:type="pct" w:w="5000"/>'))
            tPr.append(parse_xml(f'<w:tblLayout {nsdecls("w")} w:type="fixed"/>'))
            # Light borders
            tPr.append(parse_xml(
                f'<w:tblBorders {nsdecls("w")}>'
                f'<w:top    w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'<w:left   w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'<w:bottom w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'<w:right  w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'<w:insideH w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'<w:insideV w:val="single" w:sz="4" w:color="CBD5E0"/>'
                f'</w:tblBorders>'
            ))
        except Exception:
            pass

        for _ri, (_lbl, _val) in enumerate(_meta_rows):
            row = meta_tbl.rows[_ri]
            # Label cell (32%)
            lc = row.cells[0]
            lc.text = ''
            lp = lc.paragraphs[0]
            lr = lp.add_run(_lbl)
            lr.bold = True
            lr.font.name = 'Calibri'
            lr.font.size = Pt(9)
            lr.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
            # Value cell (68%)
            vc = row.cells[1]
            vc.text = ''
            vp = vc.paragraphs[0]
            vr = vp.add_run(_val)
            vr.font.name = 'Calibri'
            vr.font.size = Pt(10)
            # Shading
            for _ci, _cell in enumerate(row.cells):
                shd_fill = 'EDF2F7' if _ri % 2 == 0 else 'FAFBFC'
                _cell._tc.get_or_add_tcPr().append(
                    parse_xml(f'<w:shd {nsdecls("w")} w:val="clear" w:color="auto" w:fill="{shd_fill}"/>')
                )
            # Column widths
            try:
                from docx.oxml.ns import qn as _qn
                for _ci, (_cell, _pct) in enumerate(zip(row.cells, [1700, 3300])):
                    tcPr = _cell._tc.get_or_add_tcPr()
                    _existing = tcPr.findall(f'{{{nsdecls("w").split()[1].split("=")[1].strip(chr(34))}}}tcW')
                    for _ex in tcPr.findall(f'{_qn("w:tcW")}'):
                        tcPr.remove(_ex)
                    tcPr.append(parse_xml(f'<w:tcW {nsdecls("w")} w:type="pct" w:w="{_pct}"/>'))
            except Exception:
                pass

        doc.add_paragraph()  # spacer after metadata table

        # ── Bottom navy rule + tagline ─────────────────────────────────────
        tagline_p = doc.add_paragraph()
        tagline_pPr = tagline_p._p.get_or_add_pPr()
        tagline_pPr.append(parse_xml(
            f'<w:pBdr {nsdecls("w")}>'
            f'<w:top w:val="single" w:sz="12" w:space="1" w:color="1B2A4A"/>'
            f'</w:pBdr>'
        ))
        tagline_p.alignment = WD_ALIGN_PARAGRAPH.CENTER
        tl_run = tagline_p.add_run(
            'الحوكمة • المخاطر • الامتثال' if is_arabic else 'Governance • Risk • Compliance'
        )
        tl_run.font.name = 'Calibri'
        tl_run.font.size = Pt(9)
        tl_run.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
        tagline_p.paragraph_format.space_before = Pt(8)

        # ── Page break before body ────────────────────────────────────────
        doc.add_page_break()

        # ── KPMG-STYLE TABLE OF CONTENTS PAGE ────────────────────────────
        try:
            if is_arabic:
                _toc_title = 'المحتويات'
                _toc_secs = [
                    ('1', 'الرؤية والأهداف الاستراتيجية'),
                    ('2', 'الركائز الاستراتيجية'),
                    ('3', 'تحليل الفجوات'),
                    ('4', 'خارطة الطريق التنفيذية'),
                    ('5', 'مؤشرات الأداء الرئيسية'),
                    ('6', 'تقييم الثقة والمخاطر'),
                ]
            else:
                _toc_title = 'Contents'
                _toc_secs = [
                    ('1', 'Vision & Objectives'),
                    ('2', 'Strategic Pillars'),
                    ('3', 'Gap Analysis'),
                    ('4', 'Implementation Roadmap'),
                    ('5', 'Key Performance Indicators'),
                    ('6', 'Confidence Assessment & Risks'),
                ]
            # TOC heading
            _th = doc.add_heading(_toc_title, level=1)
            _th.alignment = WD_ALIGN_PARAGRAPH.RIGHT if is_arabic else WD_ALIGN_PARAGRAPH.LEFT
            for _run in _th.runs:
                _run.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
                _run.font.name = 'Calibri'
                _run.font.size = Pt(22)
            # Navy divider under heading
            _hr = doc.add_paragraph()
            _hr._p.get_or_add_pPr().append(parse_xml(
                f'<w:pBdr {nsdecls("w")}>'
                f'<w:bottom w:val="single" w:sz="8" w:space="1" w:color="1B2A4A"/>'
                f'</w:pBdr>'
            ))
            _hr.paragraph_format.space_after = Pt(6)
            # TOC entries
            for _sn, _st in _toc_secs:
                _ep = doc.add_paragraph()
                _ep.alignment = WD_ALIGN_PARAGRAPH.RIGHT if is_arabic else WD_ALIGN_PARAGRAPH.LEFT
                _nr = _ep.add_run(f'{_sn}  ')
                _nr.bold = True
                _nr.font.name = 'Calibri'
                _nr.font.size = Pt(10)
                _nr.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
                _tr = _ep.add_run(_st)
                _tr.font.name = 'Calibri'
                _tr.font.size = Pt(10)
                _ep.paragraph_format.space_before = Pt(4)
                _ep.paragraph_format.space_after  = Pt(4)
                # Light bottom border per entry (KPMG-style divider dots)
                _ep._p.get_or_add_pPr().append(parse_xml(
                    f'<w:pBdr {nsdecls("w")}>'
                    f'<w:bottom w:val="dotted" w:sz="4" w:space="1" w:color="CBD5E0"/>'
                    f'</w:pBdr>'
                ))
            # Tagline
            doc.add_paragraph()
            _tl = doc.add_paragraph()
            _tl_r = _tl.add_run(
                'هذه الوثيقة سرية ومعدة حصراً للاستخدام الداخلي.' if is_arabic else
                'This document is confidential and prepared exclusively for internal use. '
                'All recommendations are grounded in the diagnostic data provided.'
            )
            _tl_r.font.name = 'Calibri'
            _tl_r.font.size = Pt(8)
            _tl_r.font.color.rgb = RGBColor(0x71, 0x80, 0x96)
            doc.add_page_break()
        except Exception as _toc_docx_err:
            print(f'DOCX TOC (non-fatal): {_toc_docx_err}', flush=True)
            doc.add_page_break()

    except Exception as _cover_err:
        print(f"DOCX cover page (non-fatal): {_cover_err}", flush=True)
        # Fallback: simple heading
        try:
            add_rtl_heading((doc_type or filename.replace('_', ' ').title()), 0)
        except Exception:
            pass
    
    # ---- Process content line by line ----
    # First, ensure proper markdown formatting for reliable parsing
    try:
        content = ensure_markdown_formatting(content)
    except Exception as fmt_err:
        print(f"DOCX WARNING: ensure_markdown_formatting failed: {fmt_err}", flush=True)
    
    # Strip AI-generated metadata table (download function adds proper header)
    import re as re_docx
    content = re_docx.sub(r'^\s*\|\s*\|\s*\|\s*\n\|---\|---\|\s*\n(?:\|[^\n]*\|\s*\n)*', '', content, flags=re.MULTILINE)
    content = re_docx.sub(r'^\s*\|\s*\*\*(?:Document Title|عنوان الوثيقة)\*\*\s*\|[^\n]*\n(?:\|[^\n]*\n)*', '', content, flags=re.MULTILINE)
    # Also strip bold metadata lines outside tables
    content = re_docx.sub(r'^\s*\*\*(?:Document Type|Domain|Classification|Version|Status|Date|Preparation Date|Document Title|نوع الوثيقة|المجال|السرية|الإصدار|الحالة|تاريخ الإعداد|عنوان الوثيقة)\*\*\s*[^\n]+\n', '', content, flags=re.MULTILINE)
    # Strip the leading H1 title line — cover page already shows document type + domain.
    # Without this the H1 appears as a redundant large heading at the top of page 2.
    content = re_docx.sub(r'^#\s+[^\n]{1,120}\n', '', content.lstrip(), count=1)
    # Remove all [SECTION] markers globally — DB-stored content retains them from raw AI output;
    # the line-by-line check below only catches standalone-line occurrences.
    content = re_docx.sub(r'\[SECTION\]', '', content)
    
    lines = content.split('\n')
    i = 0
    
    while i < len(lines):
        try:
            line = lines[i].strip()
            
            # Skip empty lines and separators
            if not line:
                i += 1
                continue
            if line == '---' or line == '[SECTION]':
                doc.add_paragraph('')
                i += 1
                continue
            
            # Table
            if line.startswith('|') and '|' in line[1:]:
                table_data, new_idx = parse_markdown_table(lines, i)
                if table_data and len(table_data) >= 2:  # Need header + at least 1 data row
                    add_table_to_doc(doc, table_data, lang)
                elif table_data and len(table_data) == 1:
                    # Header-only table — skip it silently (data rows were stripped)
                    print(f"DOCX: Skipping header-only table: {table_data[0][:3]}...", flush=True)
                i = new_idx
                continue
            
            # Headings — check most specific first
            if line.startswith('#### '):
                add_rtl_heading(line[5:], 3)
            elif line.startswith('### '):
                add_rtl_heading(line[4:], 2)
            elif line.startswith('## '):
                add_rtl_heading(line[3:], 1)
            elif line.startswith('# '):
                try:
                    add_rtl_heading(line[2:], 0)
                except Exception:
                    add_rtl_heading(line[2:], 1)
            
            # Blockquote: > text
            elif line.startswith('> '):
                quote_text = line[2:].strip()
                # Collect consecutive blockquote lines
                bq_lines = [quote_text]
                while i + 1 < len(lines) and lines[i + 1].strip().startswith('> '):
                    i += 1
                    bq_lines.append(lines[i].strip()[2:].strip())
                bq_full = ' '.join(bq_lines)
                p = doc.add_paragraph()
                p.paragraph_format.left_indent  = Cm(1.0)
                p.paragraph_format.right_indent = Cm(0.5) if is_arabic else Cm(0)
                p.paragraph_format.space_before = Pt(6)
                p.paragraph_format.space_after  = Pt(6)
                # Add a navy left border via paragraph border XML
                try:
                    from docx.oxml.ns import qn as _qn
                    from docx.oxml   import parse_xml as _px
                    from docx.oxml.ns import nsdecls as _ns
                    pPr = p._p.get_or_add_pPr()
                    pBdr = _px(f'<w:pBdr {_ns("w")}>'
                                f'<w:left w:val="single" w:sz="18" w:space="12" w:color="1B2A4A"/>'
                                f'</w:pBdr>')
                    pPr.append(pBdr)
                except Exception:
                    pass
                # Render inline bold within blockquote
                if '**' in bq_full:
                    parts = re.split(r'\*\*(.+?)\*\*', bq_full)
                    for bq_idx, bq_part in enumerate(parts):
                        if bq_part:
                            run = p.add_run(bq_part)
                            run.bold   = (bq_idx % 2 == 1)
                            run.italic = True
                            if is_arabic:
                                set_rtl_run(run)
                else:
                    run = p.add_run(bq_full)
                    run.italic = True
                    if is_arabic:
                        set_rtl_run(run)
                if is_arabic:
                    set_rtl_paragraph(p)

            # Bullet points
            elif line.startswith('- ') or line.startswith('* ') or line.startswith('• '):
                raw_text = line[2:]
                if is_arabic:
                    p = doc.add_paragraph()
                    # Process inline bold within bullet
                    if '**' in raw_text:
                        p.add_run('• ')
                        parts = re.split(r'\*\*(.+?)\*\*', raw_text)
                        for idx_b, part in enumerate(parts):
                            if part:
                                run = p.add_run(part)
                                if idx_b % 2 == 1:
                                    run.bold = True
                                set_rtl_run(run)
                    else:
                        run = p.add_run('• ' + raw_text)
                    set_rtl_paragraph(p)
                    p.paragraph_format.left_indent = Cm(1)
                else:
                    p = doc.add_paragraph()
                    if '**' in raw_text:
                        parts = re.split(r'\*\*(.+?)\*\*', raw_text)
                        for idx_b, part in enumerate(parts):
                            if part:
                                run = p.add_run(part)
                                if idx_b % 2 == 1:
                                    run.bold = True
                    else:
                        p.add_run(raw_text)
                    try:
                        p.style = doc.styles['List Bullet']
                    except Exception:
                        # Fallback: manual bullet
                        first_run = p.runs[0] if p.runs else p.add_run('')
                        first_run.text = '• ' + first_run.text
                    p.paragraph_format.left_indent = Cm(1)
            
            # Numbered lists
            elif re.match(r'^(\d+)\.\s+(.+)', line):
                m = re.match(r'^(\d+)\.\s+(.+)', line)
                num = m.group(1)
                raw_text = m.group(2)
                if is_arabic:
                    p = doc.add_paragraph()
                    # Keep natural order - RTL will handle display
                    run = p.add_run(num + '. ' + raw_text)
                    set_rtl_paragraph(p)
                    p.paragraph_format.left_indent = Cm(1)
                else:
                    try:
                        p = doc.add_paragraph(line, style='List Number')
                    except Exception:
                        p = doc.add_paragraph(line)
            
            # Full bold line — KPMG shaded panel for callout labels
            elif line.startswith('**') and line.endswith('**'):
                raw_label = line[2:-2]
                _rl_docx = raw_label.strip().rstrip(':').lower()
                _KPMG_LABELS_DOCX = {
                    'strategic mandate', 'compliance north star',
                    'investment justification', 'vision:', 'vision',
                    'الولاية الاستراتيجية', 'النجم الشمالي للامتثال',
                    'مبرر الاستثمار', 'الرؤية الاستراتيجية:', 'الرؤية:',
                }
                if _rl_docx in _KPMG_LABELS_DOCX:
                    # Collect the body paragraph that follows this label
                    _panel_body = ''
                    _jj = lines.index(line, i) + 1 if line in lines[i:] else i + 1
                    _jj = i + 1
                    while _jj < len(lines):
                        _bp = lines[_jj].strip()
                        if not _bp:
                            _jj += 1
                            continue
                        if (_bp.startswith('#') or
                                (_bp.startswith('**') and _bp.endswith('**')) or
                                _bp.startswith('|')):
                            break
                        _panel_body = _bp
                        _jj += 1
                        break
                    # Render as KPMG-style shaded panel in DOCX
                    try:
                        from docx.oxml.ns import qn as _qn2
                        # Shaded paragraph for label
                        _lp = doc.add_paragraph()
                        _lr = _lp.add_run(raw_label)
                        _lr.bold = True
                        _lr.font.name = 'Calibri'
                        _lr.font.size = Pt(10)
                        _lr.font.color.rgb = RGBColor(0x1B, 0x2A, 0x4A)
                        _lp.paragraph_format.space_before = Pt(8)
                        _lp.paragraph_format.space_after  = Pt(2)
                        _lp.paragraph_format.left_indent  = Cm(0.4)
                        # Light blue shading on label paragraph
                        _lpPr = _lp._p.get_or_add_pPr()
                        _shd_l = parse_xml(f'<w:shd {nsdecls("w")} w:val="clear" w:color="auto" w:fill="EBF4FF"/>')
                        _lpPr.append(_shd_l)
                        # Add navy left border via paragraph border XML
                        try:
                            _pBdr = parse_xml(
                                f'<w:pBdr {nsdecls("w")}>'
                                f'<w:left w:val="single" w:sz="18" w:space="12" w:color="1B2A4A"/>'
                                f'</w:pBdr>'
                            )
                            _lpPr.append(_pBdr)
                        except Exception:
                            pass
                        if is_arabic:
                            set_rtl_paragraph(_lp)
                        # Body paragraph (shaded, no border)
                        if _panel_body:
                            _bp2 = doc.add_paragraph()
                            _br2 = _bp2.add_run(_panel_body)
                            _br2.font.name = 'Calibri'
                            _br2.font.size = Pt(10)
                            _bp2.paragraph_format.space_before = Pt(2)
                            _bp2.paragraph_format.space_after  = Pt(8)
                            _bp2.paragraph_format.left_indent  = Cm(0.4)
                            _bp2Pr = _bp2._p.get_or_add_pPr()
                            _shd_b = parse_xml(f'<w:shd {nsdecls("w")} w:val="clear" w:color="auto" w:fill="EBF4FF"/>')
                            _bp2Pr.append(_shd_b)
                            try:
                                _pBdr2 = parse_xml(
                                    f'<w:pBdr {nsdecls("w")}>'
                                    f'<w:left w:val="single" w:sz="18" w:space="12" w:color="1B2A4A"/>'
                                    f'</w:pBdr>'
                                )
                                _bp2Pr.append(_pBdr2)
                            except Exception:
                                pass
                            if is_arabic:
                                set_rtl_paragraph(_bp2)
                            i = _jj
                    except Exception as _kp_err:
                        add_rtl_paragraph(raw_label, bold=True)
                else:
                    add_rtl_paragraph(raw_label, bold=True)
            
            # Evidence/checkbox lines (☐ markers)
            elif '☐' in line or '☑' in line:
                p = doc.add_paragraph()
                if '**' in line:
                    parts = re.split(r'\*\*(.+?)\*\*', line)
                    for idx_p, part in enumerate(parts):
                        if part:
                            run = p.add_run(part)
                            if idx_p % 2 == 1:
                                run.bold = True
                            if is_arabic:
                                set_rtl_run(run)
                else:
                    run = p.add_run(line)
                    if is_arabic:
                        set_rtl_run(run)
                if is_arabic:
                    set_rtl_paragraph(p)
                p.paragraph_format.left_indent = Cm(1)
            
            # Inline bold
            elif '**' in line:
                p = doc.add_paragraph()
                parts = re.split(r'\*\*(.+?)\*\*', line)
                for idx, part in enumerate(parts):
                    if part:
                        run = p.add_run(part)
                        if idx % 2 == 1:
                            run.bold = True
                        if is_arabic:
                            set_rtl_run(run)
                if is_arabic:
                    set_rtl_paragraph(p)
            
            # Normal text
            else:
                add_rtl_paragraph(line)
            
            i += 1
        
        except Exception as line_err:
            print(f"DOCX WARNING: Error on line {i}: '{lines[i][:80] if i < len(lines) else '?'}' - {line_err}", flush=True)
            try:
                add_rtl_paragraph(lines[i].strip() if i < len(lines) else '')
            except Exception:
                pass
            i += 1
    
    # Save to BytesIO and return bytes
    buffer = BytesIO()
    doc.save(buffer)
    buffer.seek(0)
    return buffer.getvalue()

    # End of _build_docx_bytes


@app.route('/api/generate-docx', methods=['POST'])
@login_required
def api_generate_docx():
    """Generate Word document from content."""
    from io import BytesIO
    import re

    try:
        data = request.json
    except Exception as je:
        return jsonify({'error': f'Invalid JSON: {str(je)}'}), 400

    if not data:
        return jsonify({'error': 'No data received'}), 400

    content = data.get('content', '')
    filename = data.get('filename', 'document')
    lang = data.get('language', 'en')
    org_name = data.get('org_name', '').strip()
    sector   = data.get('sector', '').strip()
    doc_type = data.get('doc_type', 'Strategy Document')
    domain   = data.get('domain', '')

    try:
        log_action(session.get('user_id'), 'export_docx', {'filename': filename})
    except Exception:
        pass

    print("=" * 60, flush=True)
    print(f"DOCX GENERATION - lang={lang}, filename={filename}", flush=True)
    print(f"Content length: {len(content)}", flush=True)
    print("=" * 60, flush=True)

    if not content or not content.strip():
        return jsonify({'error': 'No content to generate document'}), 400

    try:
        doc_bytes = _build_docx_bytes(content, filename, lang, org_name, sector, doc_type, domain)

        from flask import Response, stream_with_context

        def generate_docx_stream():
            chunk_size = 65536
            offset = 0
            while offset < len(doc_bytes):
                yield doc_bytes[offset:offset + chunk_size]
                offset += chunk_size

        safe_name = filename.replace('"', '').replace('\n', '').replace('\r', '')
        return Response(
            stream_with_context(generate_docx_stream()),
            mimetype='application/vnd.openxmlformats-officedocument.wordprocessingml.document',
            headers={
                'Content-Disposition': f'attachment; filename="{safe_name}.docx"',
                'Content-Length': str(len(doc_bytes)),
                'Cache-Control': 'no-cache',
                'X-Content-Type-Options': 'nosniff'
            }
        )
    except ImportError as ie:
        print(f"DOCX IMPORT ERROR: {ie}", flush=True)
        import traceback; traceback.print_exc()
        return jsonify({'error': f'Word generation not available: {str(ie)}'}), 500
    except Exception as e:
        print(f"DOCX GENERATION ERROR: {str(e)}", flush=True)
        import traceback; print(traceback.format_exc(), flush=True)
        return jsonify({'error': f'Document generation failed: {str(e)}'}), 500

@app.route('/api/generate-pdf', methods=['POST'])
@login_required
def api_generate_pdf():
    """Generate PDF document from content with Arabic support."""
    from io import BytesIO
    import os
    import glob
    
    data = request.json
    content = data.get('content', '')
    filename = data.get('filename', 'document')
    lang = data.get('language', 'en')
    org_name_pdf = data.get('org_name', '').strip() or 'The Organization'
    sector_pdf   = data.get('sector', '').strip()
    doc_type_pdf = data.get('doc_type', 'Strategy Document')
    domain_pdf   = data.get('domain', '').strip()
    
    try:
        log_action(session.get('user_id'), 'export_pdf', {'filename': filename})
    except Exception:
        pass
    
    try:
        from reportlab.lib.pagesizes import A4
        from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
        from reportlab.lib.enums import TA_RIGHT, TA_LEFT, TA_CENTER
        from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, PageBreak
        from reportlab.lib.units import inch, cm
        from reportlab.lib import colors
        from reportlab.pdfbase import pdfmetrics
        from reportlab.pdfbase.ttfonts import TTFont
        
        # For Arabic text
        is_arabic = lang == 'ar'
        arabic_font_name = 'Helvetica'  # Default fallback
        arabic_font_bold = 'Helvetica-Bold'
        
        if is_arabic:
            try:
                import arabic_reshaper
                from bidi.algorithm import get_display
                
                # Extended font search paths for Arabic support
                font_paths = [
                    # Noto fonts (installed via render.yaml)
                    '/usr/share/fonts/truetype/noto/NotoSansArabic-Regular.ttf',
                    '/usr/share/fonts/opentype/noto/NotoSansArabic-Regular.ttf',
                    '/usr/share/fonts/truetype/noto/NotoNaskhArabic-Regular.ttf',
                    # FreeFonts
                    '/usr/share/fonts/truetype/freefont/FreeSans.ttf',
                    '/usr/share/fonts/truetype/freefont/FreeSerif.ttf',
                    # DejaVu (has Arabic support)
                    '/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf',
                    # Liberation fonts
                    '/usr/share/fonts/truetype/liberation/LiberationSans-Regular.ttf',
                    # Local fonts
                    'static/fonts/Amiri-Regular.ttf',
                    'static/fonts/NotoSansArabic-Regular.ttf',
                    # Additional system paths
                    '/usr/share/fonts/TTF/DejaVuSans.ttf',
                    '/usr/local/share/fonts/Amiri-Regular.ttf',
                ]
                
                # Also search for any Arabic font using glob
                additional_paths = glob.glob('/usr/share/fonts/**/[Aa]rabic*.ttf', recursive=True)
                additional_paths += glob.glob('/usr/share/fonts/**/[Nn]oto*[Aa]rabic*.ttf', recursive=True)
                additional_paths += glob.glob('/usr/share/fonts/**/[Aa]miri*.ttf', recursive=True)
                font_paths = additional_paths + font_paths
                
                font_registered = False
                for font_path in font_paths:
                    if os.path.exists(font_path):
                        try:
                            pdfmetrics.registerFont(TTFont('ArabicFont', font_path))
                            arabic_font_name = 'ArabicFont'
                            arabic_font_bold = 'ArabicFont'
                            font_registered = True
                            print(f"✅ Registered Arabic font: {font_path}", flush=True)
                            break
                        except Exception as font_error:
                            print(f"⚠️ Failed to register font {font_path}: {font_error}", flush=True)
                            continue
                
                if not font_registered:
                    print("⚠️ No Arabic font found, PDF will show boxes for Arabic text", flush=True)
                    # List available fonts for debugging
                    for search_path in ['/usr/share/fonts/truetype/', '/usr/share/fonts/']:
                        if os.path.exists(search_path):
                            print(f"Available fonts in {search_path}:", flush=True)
                            for item in os.listdir(search_path)[:10]:
                                print(f"  - {item}", flush=True)
                
            except ImportError as ie:
                print(f"⚠️ Arabic libraries not available: {ie}", flush=True)
                # Fallback if arabic libraries not available
                def get_display(text):
                    return text
                class _FallbackReshaper:
                    def reshape(self, text):
                        return text
                arabic_reshaper = _FallbackReshaper()
        
        # Calculate available text width for manual line wrapping
        page_width = A4[0]
        text_width = page_width - 3*cm  # 1.5cm margin each side
        # CRITICAL: Use a tighter wrap width for Arabic pre-wrapping.
        # We must wrap NARROWER than ReportLab's Paragraph frame width,
        # so ReportLab never re-wraps our visually-ordered lines.
        # If ReportLab re-wraps, it splits reversed text at wrong points
        # (e.g. "تهدف" appearing alone on a line).
        arabic_wrap_width = text_width - 12  # 12pt safety margin
        
        def process_arabic(text, font_name_for_wrap=None, font_size_for_wrap=11, extra_indent=0):
            """Process Arabic text for correct display in PDF.
            
            Strategy: reshape → manual word-wrap → get_display per line → join with <br/>
            This prevents the jumbled word order that happens when get_display is applied
            to an entire paragraph and then ReportLab re-wraps it.
            
            CRITICAL: We wrap to arabic_wrap_width (narrower than frame) so ReportLab
            never needs to re-wrap our pre-wrapped lines.
            """
            if is_arabic and text:
                try:
                    text = str(text).strip()
                    if not text:
                        return text
                    
                    from reportlab.pdfbase.pdfmetrics import stringWidth
                    wrap_font = font_name_for_wrap or arabic_font_name
                    # Use tighter width to prevent ReportLab re-wrapping
                    wrap_width = arabic_wrap_width - extra_indent
                    
                    # Handle mixed content with HTML bold tags
                    if '<b>' in text or '</b>' in text:
                        import re as re_clean
                        parts = re_clean.split(r'(<b>|</b>)', text)
                        processed_parts = []
                        for part in parts:
                            if part in ('<b>', '</b>'):
                                processed_parts.append(part)
                            elif part.strip():
                                reshaped = arabic_reshaper.reshape(part)
                                processed_parts.append(get_display(reshaped))
                            else:
                                processed_parts.append(part)
                        return ''.join(processed_parts)
                    
                    # Step 1: Reshape for letter joining
                    reshaped = arabic_reshaper.reshape(text)
                    
                    # Step 2: Check if text fits in one line (most headings, short text)
                    total_width = stringWidth(reshaped, wrap_font, font_size_for_wrap)
                    if total_width <= wrap_width:
                        # Single line — just get_display the whole thing
                        return get_display(reshaped)
                    
                    # Step 3: Manual word-wrap for multi-line text
                    words = reshaped.split(' ')
                    lines = []
                    current_line_words = []
                    current_width = 0
                    space_width = stringWidth(' ', wrap_font, font_size_for_wrap)
                    
                    for word in words:
                        word_width = stringWidth(word, wrap_font, font_size_for_wrap)
                        test_width = current_width + word_width + (space_width if current_line_words else 0)
                        
                        if test_width > wrap_width and current_line_words:
                            # Line is full — wrap to next line
                            line_text = ' '.join(current_line_words)
                            lines.append(get_display(line_text))
                            current_line_words = [word]
                            current_width = word_width
                        else:
                            current_line_words.append(word)
                            current_width = test_width
                    
                    # Last line
                    if current_line_words:
                        line_text = ' '.join(current_line_words)
                        lines.append(get_display(line_text))
                    
                    # Step 4: Join with <br/> for ReportLab Paragraph
                    if len(lines) > 1:
                        return '<br/>'.join(lines)
                    elif lines:
                        return lines[0]
                    else:
                        return get_display(reshaped)
                    
                except Exception as e:
                    print(f"Arabic processing warning: {e}", flush=True)
                    return text
            return text
        
        def process_arabic_table(text, col_width, font_size=9):
            """Process Arabic text for table cells with specific column width."""
            if is_arabic and text:
                try:
                    text = str(text).strip()
                    if not text:
                        return text
                    
                    from reportlab.pdfbase.pdfmetrics import stringWidth
                    reshaped = arabic_reshaper.reshape(text)
                    
                    # Check if fits in one line
                    total_w = stringWidth(reshaped, arabic_font_name, font_size)
                    cell_width = col_width - 16  # subtract padding + safety margin
                    if total_w <= cell_width:
                        return get_display(reshaped)
                    
                    # Wrap strictly within cell width - no overflow tolerance
                    words = reshaped.split(' ')
                    lines = []
                    current_line_words = []
                    current_width = 0
                    space_width = stringWidth(' ', arabic_font_name, font_size)
                    
                    for word in words:
                        word_width = stringWidth(word, arabic_font_name, font_size)
                        test_width = current_width + word_width + (space_width if current_line_words else 0)
                        
                        if test_width > cell_width and current_line_words:
                            line_text = ' '.join(current_line_words)
                            lines.append(get_display(line_text))
                            current_line_words = [word]
                            current_width = word_width
                        else:
                            current_line_words.append(word)
                            current_width = test_width
                    
                    if current_line_words:
                        line_text = ' '.join(current_line_words)
                        lines.append(get_display(line_text))
                    
                    return '<br/>'.join(lines) if len(lines) > 1 else (lines[0] if lines else get_display(reshaped))
                    
                except Exception as e:
                    return text
            return text
        
        # Create PDF buffer
        buffer = BytesIO()
        doc = SimpleDocTemplate(
            buffer,
            pagesize=A4,
            rightMargin=1.5*cm,
            leftMargin=1.5*cm,
            topMargin=2.4*cm,    # room for running header rule
            bottomMargin=2.2*cm  # room for page number footer
        )
        
        # Styles
        styles = getSampleStyleSheet()
        
        # Custom styles
        if is_arabic:
            title_style = ParagraphStyle(
                'ArabicTitle',
                parent=styles['Title'],
                alignment=TA_RIGHT,
                fontSize=24,
                spaceAfter=30,
                fontName=arabic_font_bold,
            )
            heading1_style = ParagraphStyle(
                'ArabicH1',
                parent=styles['Heading1'],
                alignment=TA_RIGHT,
                fontSize=18,
                spaceAfter=12,
                spaceBefore=20,
                textColor=colors.HexColor('#1a365d'),
                fontName=arabic_font_bold,
            )
            heading2_style = ParagraphStyle(
                'ArabicH2',
                parent=styles['Heading2'],
                alignment=TA_RIGHT,
                fontSize=14,
                spaceAfter=10,
                spaceBefore=15,
                textColor=colors.HexColor('#2d3748'),
                fontName=arabic_font_bold,
            )
            normal_style = ParagraphStyle(
                'ArabicNormal',
                parent=styles['Normal'],
                alignment=TA_RIGHT,
                fontSize=11,
                spaceAfter=8,
                leading=18,
                fontName=arabic_font_name,
            )
            bullet_style = ParagraphStyle(
                'ArabicBullet',
                parent=styles['Normal'],
                alignment=TA_RIGHT,
                fontSize=11,
                spaceAfter=6,
                rightIndent=20,
                fontName=arabic_font_name,
            )
            numbered_style = ParagraphStyle(
                'ArabicNumbered',
                parent=styles['Normal'],
                alignment=TA_RIGHT,
                fontSize=11,
                spaceAfter=6,
                rightIndent=20,
                fontName=arabic_font_name,
            )
            # Arabic callout label style — full-bold lines like **الولاية الاستراتيجية**
            callout_style = ParagraphStyle(
                'ArabicCallout',
                parent=styles['Normal'],
                alignment=TA_RIGHT,
                fontSize=11,
                spaceBefore=14,
                spaceAfter=4,
                leading=18,
                textColor=colors.HexColor('#1B2A4A'),
                rightIndent=4,
                fontName=arabic_font_bold,
            )
        else:
            title_style = ParagraphStyle(
                'CustomTitle',
                parent=styles['Title'],
                fontSize=24,
                spaceAfter=30,
                textColor=colors.HexColor('#1a365d')
            )
            heading1_style = ParagraphStyle(
                'CustomH1',
                parent=styles['Heading1'],
                fontSize=18,
                spaceAfter=12,
                spaceBefore=20,
                textColor=colors.HexColor('#1a365d')
            )
            heading2_style = ParagraphStyle(
                'CustomH2',
                parent=styles['Heading2'],
                fontSize=14,
                spaceAfter=10,
                spaceBefore=15,
                textColor=colors.HexColor('#2d3748')
            )
            normal_style = ParagraphStyle(
                'CustomNormal',
                parent=styles['Normal'],
                fontSize=11,
                spaceAfter=8,
                leading=16
            )
            bullet_style = ParagraphStyle(
                'CustomBullet',
                parent=styles['Normal'],
                fontSize=11,
                spaceAfter=6,
                leftIndent=20,
                bulletIndent=10
            )
            numbered_style = ParagraphStyle(
                'CustomNumbered',
                parent=styles['Normal'],
                fontSize=11,
                spaceAfter=6,
                leftIndent=20
            )
            # Callout label style — for full-bold lines like **Strategic Mandate**
            # Adds breathing room above so labels don't merge into preceding prose.
            callout_style = ParagraphStyle(
                'CustomCallout',
                parent=styles['Normal'],
                fontSize=11,
                spaceBefore=14,
                spaceAfter=4,
                leading=16,
                textColor=colors.HexColor('#1B2A4A'),
                leftIndent=4,
            )

            # ── KPMG-style callout panel styles ─────────────────────────────
            # Renders Strategic Mandate / Compliance North Star /
            # Investment Justification / Vision: blocks as shaded pull-quote
            # panels with a left navy accent bar — matching KPMG Better
            # Business Reporting visual language.
            kpmg_panel_label_style = ParagraphStyle(
                'KPMGPanelLabel',
                parent=styles['Normal'],
                fontSize=10,
                leading=14,
                textColor=colors.HexColor('#1B2A4A'),
                fontName='Helvetica-Bold',
                alignment=TA_RIGHT if is_arabic else TA_LEFT,
            )
            kpmg_panel_body_style = ParagraphStyle(
                'KPMGPanelBody',
                parent=styles['Normal'],
                fontSize=10,
                leading=15,
                textColor=colors.HexColor('#2D3748'),
                fontName=arabic_font_name if is_arabic else 'Helvetica',
                alignment=TA_RIGHT if is_arabic else TA_LEFT,
            )

            # Labels that trigger the shaded-panel treatment
            _KPMG_CALLOUT_LABELS = {
                'strategic mandate', 'compliance north star',
                'investment justification', 'vision:', 'vision',
                'الولاية الاستراتيجية', 'النجم الشمالي للامتثال',
                'مبرر الاستثمار', 'الرؤية الاستراتيجية:', 'الرؤية:',
            }

            def _make_kpmg_panel(label_txt, body_txt, avail_w):
                """Return a KPMG-style shaded callout panel (label + body)."""
                from reportlab.lib.colors import HexColor as _HC
                PANEL_BG   = _HC('#F0F4F8')
                BORDER_COL = _HC('#1B2A4A')
                accent = Table([['']], colWidths=[5], rowHeights=[None])
                accent.setStyle(TableStyle([
                    ('BACKGROUND',    (0,0),(0,0), BORDER_COL),
                    ('TOPPADDING',    (0,0),(0,0), 0),
                    ('BOTTOMPADDING', (0,0),(0,0), 0),
                    ('LEFTPADDING',   (0,0),(0,0), 0),
                    ('RIGHTPADDING',  (0,0),(0,0), 0),
                ]))
                text_w = avail_w - 5 - 8
                if is_arabic:
                    _lbl = process_arabic(label_txt, arabic_font_bold, 10)
                    _bdy = process_arabic(body_txt,  arabic_font_name, 10)
                else:
                    _lbl = label_txt
                    _bdy = body_txt
                _cells = []
                if _lbl.strip():
                    _cells.append(Paragraph(f'<b>{_lbl}</b>', kpmg_panel_label_style))
                if _bdy.strip():
                    _cells.append(Paragraph(_bdy, kpmg_panel_body_style))
                from reportlab.platypus import KeepInFrame as _KIF
                kif = _KIF(text_w, 800, _cells, mode='shrink')
                outer = Table([[accent, kif]], colWidths=[5, text_w])
                outer.setStyle(TableStyle([
                    ('BACKGROUND',    (1,0),(1,0), PANEL_BG),
                    ('TOPPADDING',    (0,0),(-1,-1), 10),
                    ('BOTTOMPADDING', (0,0),(-1,-1), 10),
                    ('LEFTPADDING',   (1,0),(1,0), 12),
                    ('RIGHTPADDING',  (1,0),(1,0), 12),
                    ('LEFTPADDING',   (0,0),(0,0), 0),
                    ('RIGHTPADDING',  (0,0),(0,0), 0),
                    ('VALIGN',        (0,0),(-1,-1), 'TOP'),
                ]))
                return outer

        story = []
        
        # ══════════════════════════════════════════════════════════════════
        # BIG-4 COVER PAGE
        # ══════════════════════════════════════════════════════════════════
        try:
            from reportlab.platypus import Image as RLImage
            from reportlab.platypus import HRFlowable
            from reportlab.lib.colors import HexColor, white
            
            # ── Resolve org logo ──────────────────────────────────────────
            user_logo = None
            if session.get('user_id'):
                user_row = get_db().execute('SELECT logo_path FROM users WHERE id = ?', (session['user_id'],)).fetchone()
                if user_row and user_row['logo_path'] and os.path.isfile(user_row['logo_path']):
                    user_logo = user_row['logo_path']

            NAVY     = HexColor('#1B2A4A')
            MIDBLUE  = HexColor('#2E4B8A')
            GOLD     = HexColor('#C9A84C')
            LIGHTGREY= HexColor('#F4F6F9')
            TEXT_MED = HexColor('#4A5568')
            page_w   = A4[0] - 3*cm   # usable width between margins

            # ── Cover styles ──────────────────────────────────────────────
            cover_title_style = ParagraphStyle(
                'CoverDocTitle',
                fontName='Helvetica-Bold',
                fontSize=28,
                textColor=NAVY,
                leading=34,
                spaceAfter=8,
                alignment=TA_LEFT,
            )
            cover_sub_style = ParagraphStyle(
                'CoverSubtitle',
                fontName='Helvetica',
                fontSize=13,
                textColor=MIDBLUE,
                leading=18,
                spaceAfter=4,
                alignment=TA_LEFT,
            )
            cover_label_style = ParagraphStyle(
                'CoverLabel',
                fontName='Helvetica-Bold',
                fontSize=8,
                textColor=TEXT_MED,
                leading=12,
                spaceAfter=1,
                alignment=TA_LEFT,
            )
            cover_value_style = ParagraphStyle(
                'CoverValue',
                fontName='Helvetica',
                fontSize=10,
                textColor=NAVY,
                leading=14,
                spaceAfter=6,
                alignment=TA_LEFT,
            )
            cover_org_style = ParagraphStyle(
                'CoverOrg',
                fontName='Helvetica-Bold',
                fontSize=16,
                textColor=white,
                leading=20,
                alignment=TA_LEFT,
            )
            cover_prepared_style = ParagraphStyle(
                'CoverPrepared',
                fontName='Helvetica',
                fontSize=9,
                textColor=HexColor('#718096'),
                leading=14,
                alignment=TA_LEFT,
            )

            # If Arabic, mirror alignments
            if is_arabic:
                for _cs in [cover_title_style, cover_sub_style, cover_label_style,
                            cover_value_style, cover_org_style, cover_prepared_style]:
                    _cs.alignment = TA_RIGHT

            import datetime
            today_str = datetime.date.today().strftime('%d %B %Y')

            # ── BLOCK 1: Navy top bar with org name ───────────────────────
            org_display = org_name_pdf if org_name_pdf != 'The Organization' else ''
            bar_content = org_display if org_display else ('Mizan GRC Platform')

            if is_arabic:
                bar_text = process_arabic(bar_content, arabic_font_bold, 14)
            else:
                bar_text = bar_content

            bar_para = Paragraph(bar_text, cover_org_style)
            bar_table = Table(
                [[bar_para]],
                colWidths=[page_w],
            )
            bar_table.setStyle(TableStyle([
                ('BACKGROUND',    (0,0), (-1,-1), NAVY),
                ('TOPPADDING',    (0,0), (-1,-1), 18),
                ('BOTTOMPADDING', (0,0), (-1,-1), 18),
                ('LEFTPADDING',   (0,0), (-1,-1), 20),
                ('RIGHTPADDING',  (0,0), (-1,-1), 20),
            ]))
            story.append(bar_table)
            story.append(Spacer(1, 0.5*inch))

            # ── BLOCK 2: Logo (if available) ──────────────────────────────
            if user_logo:
                try:
                    logo_img = RLImage(user_logo, width=1.6*inch, height=1.0*inch)
                    logo_img.hAlign = 'LEFT' if not is_arabic else 'RIGHT'
                    story.append(logo_img)
                    story.append(Spacer(1, 0.25*inch))
                except Exception:
                    pass

            # ── BLOCK 3: Document title ───────────────────────────────────
            doc_label = doc_type_pdf
            # Always derive the subtitle from the filename — it contains both
            # the domain AND the specific document subject (e.g. "Cyber Security
            # Endpoint Security Policy" or "Cyber Security Strategy").
            # Falling back to domain_pdf alone would only show "Cyber Security".
            domain_label = filename.replace('_', ' ').title()

            if is_arabic:
                doc_label_text   = process_arabic(doc_label,    arabic_font_bold, 28)
                domain_label_text= process_arabic(domain_label, arabic_font_name, 13)
            else:
                doc_label_text    = doc_label
                domain_label_text = domain_label

            story.append(Paragraph(doc_label_text, cover_title_style))
            story.append(Paragraph(domain_label_text, cover_sub_style))
            story.append(Spacer(1, 0.15*inch))
            story.append(HRFlowable(
                width=page_w,
                thickness=3,
                color=GOLD,
                spaceAfter=0.3*inch,
            ))

            # ── BLOCK 4: Metadata info box ────────────────────────────────
            if is_arabic:
                meta_rows = [
                    ['نوع الوثيقة',    doc_type_pdf],
                    ['القطاع',          sector_pdf or '—'],
                    ['التصنيف',         'سري'],
                    ['الإصدار',         '1.0'],
                    ['الحالة',          'مسودة'],
                    ['تاريخ الإعداد',   today_str],
                    ['أُعدّ بواسطة',    'منصة ميزان GRC'],
                ]
            else:
                meta_rows = [
                    ['Document Type',   doc_type_pdf],
                    ['Sector',          sector_pdf or '—'],
                    ['Classification',  'Confidential'],
                    ['Version',         '1.0'],
                    ['Status',          'Draft'],
                    ['Prepared',        today_str],
                    ['Prepared by',     'Mizan GRC Platform'],
                ]

            meta_table_data = []
            for label, value in meta_rows:
                if is_arabic:
                    l_para = Paragraph(process_arabic(label, arabic_font_bold, 8),  cover_label_style)
                    v_para = Paragraph(process_arabic(value, arabic_font_name, 10), cover_value_style)
                else:
                    l_para = Paragraph(f'<b>{label}</b>', cover_label_style)
                    v_para = Paragraph(value,              cover_value_style)
                meta_table_data.append([l_para, v_para])

            col1 = page_w * 0.32
            col2 = page_w * 0.68
            meta_table = Table(meta_table_data, colWidths=[col1, col2])
            meta_table.setStyle(TableStyle([
                ('BACKGROUND',    (0,0), (-1,-1), LIGHTGREY),
                ('TOPPADDING',    (0,0), (-1,-1), 6),
                ('BOTTOMPADDING', (0,0), (-1,-1), 6),
                ('LEFTPADDING',   (0,0), (-1,-1), 14),
                ('RIGHTPADDING',  (0,0), (-1,-1), 14),
                ('LINEBELOW',     (0,0), (-1,-2), 0.5, HexColor('#CBD5E0')),
                ('VALIGN',        (0,0), (-1,-1), 'MIDDLE'),
            ]))
            story.append(meta_table)
            story.append(Spacer(1, 0.35*inch))

            # ── BLOCK 5: Navy bottom accent bar ───────────────────────────
            story.append(HRFlowable(
                width=page_w,
                thickness=6,
                color=NAVY,
                spaceAfter=0.1*inch,
            ))
            if is_arabic:
                footer_note = process_arabic('الحوكمة • المخاطر • الامتثال', arabic_font_name, 9)
            else:
                footer_note = 'Governance • Risk • Compliance'
            story.append(Paragraph(footer_note, cover_prepared_style))

            # ── Page break — body starts on page 2 (cover) ─────────────
            story.append(PageBreak())

            # ── KPMG-STYLE TABLE OF CONTENTS PAGE ────────────────────────
            try:
                toc_title_style = ParagraphStyle(
                    'TOCTitle', fontName='Helvetica-Bold', fontSize=22,
                    textColor=NAVY, leading=28, spaceAfter=6,
                    alignment=TA_RIGHT if is_arabic else TA_LEFT,
                )
                toc_entry_style = ParagraphStyle(
                    'TOCEntry', fontName='Helvetica', fontSize=10,
                    textColor=colors.HexColor('#2D3748'), leading=18,
                    alignment=TA_RIGHT if is_arabic else TA_LEFT,
                )
                toc_num_style = ParagraphStyle(
                    'TOCNum', fontName='Helvetica-Bold', fontSize=10,
                    textColor=NAVY, leading=18,
                    alignment=TA_RIGHT if is_arabic else TA_LEFT,
                )
                if is_arabic:
                    _toc_title_txt = process_arabic('المحتويات', arabic_font_bold, 22)
                    _toc_sections = [
                        ('1', 'الرؤية والأهداف الاستراتيجية'),
                        ('2', 'الركائز الاستراتيجية'),
                        ('3', 'تحليل الفجوات'),
                        ('4', 'خارطة الطريق التنفيذية'),
                        ('5', 'مؤشرات الأداء الرئيسية'),
                        ('6', 'تقييم الثقة والمخاطر'),
                    ]
                else:
                    _toc_title_txt = 'Contents'
                    _toc_sections = [
                        ('1', 'Vision & Objectives'),
                        ('2', 'Strategic Pillars'),
                        ('3', 'Gap Analysis'),
                        ('4', 'Implementation Roadmap'),
                        ('5', 'Key Performance Indicators'),
                        ('6', 'Confidence Assessment & Risks'),
                    ]
                story.append(Paragraph(_toc_title_txt, toc_title_style))
                story.append(HRFlowable(width=page_w, thickness=2,
                                        color=NAVY, spaceAfter=0.25*inch))
                for _sn, _st in _toc_sections:
                    if is_arabic:
                        _sn_t = process_arabic(_sn, arabic_font_bold, 10)
                        _st_t = process_arabic(_st, arabic_font_name, 10)
                    else:
                        _sn_t, _st_t = _sn, _st
                    _toc_row = Table(
                        [[Paragraph(f'<b>{_sn_t}</b>', toc_num_style),
                          Paragraph(_st_t, toc_entry_style)]],
                        colWidths=[page_w * 0.08, page_w * 0.92],
                    )
                    _toc_row.setStyle(TableStyle([
                        ('LINEBELOW',     (0,0), (-1,-1), 0.4, HexColor('#CBD5E0')),
                        ('TOPPADDING',    (0,0), (-1,-1), 6),
                        ('BOTTOMPADDING', (0,0), (-1,-1), 6),
                        ('LEFTPADDING',   (0,0), (-1,-1), 0),
                        ('RIGHTPADDING',  (0,0), (-1,-1), 0),
                        ('VALIGN',        (0,0), (-1,-1), 'MIDDLE'),
                    ]))
                    story.append(_toc_row)
                story.append(Spacer(1, 0.4*inch))
                _toc_tag_style = ParagraphStyle(
                    'TOCTagline', fontName='Helvetica', fontSize=9,
                    textColor=colors.HexColor('#718096'), leading=14,
                    alignment=TA_RIGHT if is_arabic else TA_LEFT,
                )
                _tagline = (
                    'This document is confidential and prepared exclusively for internal use. '
                    'All recommendations are grounded in the diagnostic data provided.'
                ) if not is_arabic else process_arabic(
                    'هذه الوثيقة سرية ومعدة حصراً للاستخدام الداخلي. ' +
                    'جميع التوصيات مبنية على بيانات التشخيص المقدمة.',
                    arabic_font_name, 9)
                story.append(Paragraph(_tagline, _toc_tag_style))
                story.append(PageBreak())
            except Exception as _toc_err:
                print(f'PDF TOC (non-fatal): {_toc_err}', flush=True)

        except Exception as cover_err:
            # Non-fatal — fall back to simple title if cover page fails
            print(f"PDF cover page (non-fatal): {cover_err}", flush=True)
            if is_arabic:
                title_text = process_arabic(filename.replace('_', ' '), arabic_font_bold, 24)
            else:
                title_text = filename.replace('_', ' ').title()
            story.append(Paragraph(title_text, title_style))
            story.append(Spacer(1, 0.3*inch))

        # Parse markdown content
        # CRITICAL: Run same cleanup as DOCX path
        import re as re_pdf
        try:
            content = ensure_markdown_formatting(content)
        except Exception as fmt_err:
            print(f"PDF WARNING: ensure_markdown_formatting failed: {fmt_err}", flush=True)
        # Strip AI-generated metadata table (PDF adds its own title)
        content = re_pdf.sub(r'^\s*\|\s*\|\s*\|\s*\n\|---\|---\|\s*\n(?:\|[^\n]*\|\s*\n)*', '', content, flags=re_pdf.MULTILINE)
        content = re_pdf.sub(r'^\s*\|\s*\*\*(?:Document Title|عنوان الوثيقة)\*\*\s*\|[^\n]*\n(?:\|[^\n]*\n)*', '', content, flags=re_pdf.MULTILINE)
        content = re_pdf.sub(r'^\s*\*\*(?:Document Type|Domain|Classification|Version|Status|Date|Preparation Date|Document Title|نوع الوثيقة|المجال|السرية|الإصدار|الحالة|تاريخ الإعداد|عنوان الوثيقة)\*\*\s*[^\n]+\n', '', content, flags=re_pdf.MULTILINE)
        # Strip the leading H1 title — cover page already shows document type + domain.
        # This prevents a redundant large title appearing at the top of body page 2.
        # Strip unconditionally: the first line starting with "# " followed by non-heading text.
        content = re_pdf.sub(r'^#\s+[^\n]{1,120}\n', '', content.lstrip(), count=1)
        
        # ══════════════════════════════════════════════════════════════════════
        # PDF PRE-PROCESSOR: Fix all structural issues in one regex pass BEFORE
        # the line-by-line parser runs. This is the permanent fix — the parser
        # always receives clean, well-formed markdown.
        # ══════════════════════════════════════════════════════════════════════
        def _preprocess_pdf_content(text: str) -> str:
            # 0. Split packed numbered-section lines (BigFour narrative pattern)
            _BIGFOUR_RE = re_pdf.compile(
                r'(?<!\*)\b(Strategic Mandate|Compliance North Star|Investment Justification'
                r'|Vision:|الولاية الاستراتيجية|النجم الشمالي للامتثال|مبرر الاستثمار|الرؤية:)',
                re_pdf.IGNORECASE
            )
            def _split_packed_pdf(text_in):
                out = []
                for line in text_in.split('\n'):
                    s = line.strip()
                    has_num = bool(
                        re_pdf.match(r'^\d\.\s+\w', s) or
                        re_pdf.match(r'^#{1,4}\s+\d\.\s+\w', s)
                    )
                    if not (has_num and len(s) > 200):
                        out.append(line)
                        continue
                    s_clean = re_pdf.sub(r'^#{1,4}\s+', '', s)
                    s_clean = _BIGFOUR_RE.sub(r'**\1**', s_clean)
                    if not re_pdf.search(r'\*\*[^*]{2,}\*\*', s_clean):
                        out.append(line)
                        continue
                    parts = re_pdf.split(r'(\*\*[^*]+\*\*)', s_clean)
                    heading = re_pdf.sub(r'[\s:]+$', '', parts[0].strip())
                    out.extend(['## ' + heading, ''])
                    i = 1
                    while i < len(parts):
                        part = parts[i].strip()
                        if re_pdf.match(r'^\*\*[^*]+\*\*$', part):
                            out.append(part)
                            if i + 1 < len(parts) and parts[i + 1].strip():
                                out.append(parts[i + 1].strip())
                            out.append('')
                            i += 2
                        else:
                            if part:
                                out.extend([part, ''])
                            i += 1
                return '\n'.join(out)
            text = _split_packed_pdf(text)

            # 1. Split every merged heading+table line:
            #    "### Strategic Objectives: | # | Obj | Target |..."
            #    → "### Strategic Objectives:\n| # | Obj | Target |..."
            def _split_htl(m):
                prefix = m.group(1)   # "#### " etc.
                rest   = m.group(2)   # "KPI #1 Guide: | Step | Action |..."
                pidx   = rest.find('|')
                if pidx <= 0:
                    return m.group(0)
                return prefix + rest[:pidx].rstrip(': \t') + '\n' + rest[pidx:].strip()
            text = re_pdf.sub(r'^(#{1,4}\s+)(.+\|.+\|.*)$', _split_htl, text, flags=re_pdf.MULTILINE)

            # 2. Strip duplicate document-cover banners (bare # H1, orphan pipe rows,
            #    and metadata key rows already present in the cover page table)
            text = re_pdf.sub(r'^#\s+[^\n|#*]{3,80}\n', '', text, flags=re_pdf.MULTILINE)
            text = re_pdf.sub(r'^\|\s*\|\s*\|?\s*\n', '', text, flags=re_pdf.MULTILINE)
            text = re_pdf.sub(r'^\|:?-+:?\|:?-+:?\|?\s*\n', '', text, flags=re_pdf.MULTILINE)
            meta_keys = (
                r'Document Title|Document Type|Domain|Regulatory Framework'
                r'|Classification|Version|Status|Preparation Date'
                r'|عنوان الوثيقة|نوع الوثيقة|المجال|السرية|الإصدار|الحالة|تاريخ الإعداد'
            )
            text = re_pdf.sub(
                rf'^\|\s*\*\*(?:{meta_keys})\*\*\s*\|[^\n]*\n',
                '', text, flags=re_pdf.MULTILINE | re_pdf.IGNORECASE
            )

            # 2b. Fix Phase roadmap tables that AI wrongly labels with Risk/Likelihood schema.
            # Pattern: a Phase N heading followed by a table whose first row is
            # 'Risk | Likelihood | Mitigation Plan | Owner' instead of the correct
            # 'Activity | Owner | Timeline | Deliverable' schema.
            def _fix_phase_risk_headers(text_in):
                # Match a Phase heading then the NEXT table header row
                phase_block_re = re_pdf.compile(
                    r'(#{1,4}\s+Phase\s+\d[^\n]*\n(?:[^\n]*\n){0,20}?'
                    r')(\|\s*Risk\s*\|[^\n]*\n(?:\|[-:]+\|[^\n]*\n)?)',
                    re_pdf.IGNORECASE | re_pdf.MULTILINE
                )
                def _replace_phase_hdr(m):
                    heading_block = m.group(1)
                    bad_hdr = m.group(2)
                    # Count data-cols from wrong header
                    n_cols = len([c for c in bad_hdr.split('|') if c.strip()]) if '|' in bad_hdr else 4
                    if n_cols == 4:
                        good_hdr = '| Activity | Owner | Timeline | Deliverable |\n|---|---|---|---|\n'
                    elif n_cols == 5:
                        good_hdr = '| # | Activity | Owner | Timeline | Deliverable |\n|---|---|---|---|---|\n'
                    else:
                        good_hdr = bad_hdr  # unknown shape — leave it
                    return heading_block + good_hdr
                return phase_block_re.sub(_replace_phase_hdr, text_in)
            text = _fix_phase_risk_headers(text)

            # 3. Collapse 4+ blank lines → 2
            text = re_pdf.sub(r'\n{4,}', '\n\n\n', text)
            # 4. Strip ALL phantom placeholder rows produced by header-injection.
            # The injector generates rows like:
            #   | # | Item | Detail 1 | Detail 2 | Detail 3 | Status |   (6-col)
            #   | # | Item | Details  | Notes    | Status   |           (5-col)
            #   | # | Item | Description | Notes |                      (4-col)
            #   | # | Item | Details |                                   (3-col)
            #   | Item | Description | Details | Notes |                 (4-col no #)
            # Also catch the 5-col default without '#'.
            _PHANTOM_PATTERNS = [
                # 6-col with #
                r'^\|?\s*\d*\s*\|?\s*#\s*\|\s*Item\s*\|\s*Detail\s*1\s*\|\s*Detail\s*2\s*\|\s*Detail\s*3\s*\|\s*Status\s*\|\s*$',
                # 5-col with #
                r'^\|?\s*\d*\s*\|?\s*#\s*\|\s*Item\s*\|\s*Details?\s*\|\s*Notes\s*\|\s*Status\s*\|\s*$',
                # 4-col with #
                r'^\|?\s*\d*\s*\|?\s*#\s*\|\s*Item\s*\|\s*Descri(?:ption|ptions)\s*\|\s*Notes\s*\|\s*$',
                # 3-col with #
                r'^\|?\s*\d*\s*\|?\s*#\s*\|\s*Item\s*\|\s*Details?\s*\|\s*$',
                # 4-col without # (Item | Description | Details | Notes)
                r'^\|\s*Item\s*\|\s*Descri(?:ption|ptions)\s*\|\s*Details?\s*\|\s*Notes\s*\|\s*$',
                # 5-col without # (Item | Details | Notes | Status | Priority)
                r'^\|\s*Item\s*\|\s*Details?\s*\|\s*Notes\s*\|\s*Status\s*\|\s*Priority\s*\|\s*$',
            ]
            for _pat in _PHANTOM_PATTERNS:
                text = re_pdf.sub(_pat, '', text, flags=re_pdf.MULTILINE)
            return text

        content = _preprocess_pdf_content(content)

        # ══════════════════════════════════════════════════════════════════════
        # SMART COLUMN WIDTH ENGINE
        # Replaces all fragile elif/magic-number branches with one function that:
        #   1. Measures each header cell with stringWidth() — header ALWAYS fits
        #   2. Classifies columns as narrow/medium/wide by keyword
        #   3. Distributes remaining space proportionally
        # Self-adapts to any table — no per-table tuning ever needed again.
        # ══════════════════════════════════════════════════════════════════════
        from reportlab.pdfbase.pdfmetrics import stringWidth as _sw

        _NARROW_EXACT = {
            '#','م','no','no.','r','a','c','i',          # RACI single chars (exact only)
        }
        _NARROW_KW = {
            'likelihood','الاحتمالية','impact','التأثير',
            'priority','الأولوية','status','الحالة',
            'timeframe','الإطار الزمني','timeline','الجدول الزمني',
            # NOTE: responsible/accountable/consulted/informed moved to MEDIUM —
            # their content ("Executive Management", "Board Audit Committee") is
            # 2-word role names that need ~70pt min, not the 44pt NARROW floor.
            'step','الخطوة','خطوة',
            'frequency','review frequency','reporting frequency',
            'maximum duration','approval authority',
            'current maturity','target maturity','current baseline',
            'nca ecc alignment','nca ecc control',
        }
        _MEDIUM_KW = {
            'owner','المسؤول','category','الفئة',
            'importance','الأهمية','target value','المستهدف',
            'phase','المرحلة','workstream','مسار العمل',
            'tool/system','النظام/الأداة','tool','الأداة',
            'output','المخرج','deliverable','المخرجات',
            'measurement method','verification method','compliance owner',
            'escalation path','core duties','authority',
            # RACI role columns — content is multi-word role names like
            # "Executive Management", "Board Audit Committee" → need 70pt min
            'responsible','accountable','consulted','informed',
            'المسؤول التنفيذي','المحاسب','المستشار','المطلع',
        }
        _WIDE_KW = {
            'description','الوصف','justification','المبرر',
            'recommendation','التوصية','mitigation','خطة التخفيف',
            'objective','الهدف','initiative','المبادرة',
            'action','الإجراء','gap','الفجوة','gap description',
            'activity','النشاط','key deliverable','المخرج الرئيسي',
            'calculation formula','صيغة الاحتساب','formula','الصيغة',
            'observation','الملاحظة','factor','العامل',
            'kpi description','وصف المؤشر','kpi','مؤشر',
            # Maturity assessment — "Gap Description" is longest cell content
            'dimension','البعد',
            # Policy/enforcement tables
            'requirement','consequence','violation severity','exception type',
            'trigger events',
            # Roles table
            'accountabilities','role',
        }

        def _col_weight(header_text: str) -> float:
            """Return width weight for a column based on its header keyword."""
            hl = header_text.lower().strip()
            if hl in _NARROW_EXACT or len(hl) <= 2:
                return 0.5
            if hl in _NARROW_KW or any(k in hl for k in _NARROW_KW):
                return 0.8
            if hl in _WIDE_KW or any(k in hl for k in _WIDE_KW):
                return 3.0
            if hl in _MEDIUM_KW or any(k in hl for k in _MEDIUM_KW):
                return 1.5
            return 2.0  # unknown → medium-wide

        def _content_min_usable(header_text: str) -> float:
            """Minimum USABLE width (pt) so content text never breaks mid-character.
            Based on the longest realistic word per column type at 9pt Helvetica.
            'organizational' ~56pt + 30pt buffer = 110pt for wide columns."""
            hl = header_text.lower().strip()
            if hl in _NARROW_EXACT or len(hl) <= 2:
                return 20.0   # digits / single char
            if hl in _NARROW_KW or any(k in hl for k in _NARROW_KW):
                return 44.0   # short labels like "Planning", "Medium", dates
            if hl in _WIDE_KW or any(k in hl for k in _WIDE_KW):
                return 110.0  # long words: "organizational", "cybersecurity"
            if hl in _MEDIUM_KW or any(k in hl for k in _MEDIUM_KW):
                return 72.0   # medium: "HR Director", "CISO", tool names,
                              # "Executive Management", "Board Audit Committee" 
            return 70.0       # unknown — slight uplift prevents word breaks

        # PADDING: 9pt each side = 18pt total.
        # This is the standard ReportLab table cell padding and ensures every
        # header word fits without needing any per-table override.
        _CELL_PADDING = 18

        def smart_col_widths(table_data, avail_w, font_name='Helvetica-Bold', font_size=9.0):
            """
            Compute column widths that GUARANTEE:
            1. Every header label fits without truncation (measured precisely)
            2. Content columns have enough width to wrap on word boundaries, not chars
            3. Total width == avail_w exactly
            Works for any table shape — no per-table special-casing ever needed.
            """
            if not table_data:
                return []
            headers = [re_pdf.sub(r'\*+', '', str(c)).strip() for c in table_data[0]]
            n = len(headers)
            if n == 0:
                return []

            # Per-column minimum: max(header_text + padding, content_min + padding)
            measured = []
            header_floors = []   # absolute minimum that keeps header readable
            for h in headers:
                try:
                    txt_w = _sw(h, font_name, font_size)
                except Exception:
                    txt_w = len(h) * 5.8
                hdr_floor = txt_w + _CELL_PADDING
                col_min   = max(hdr_floor, _content_min_usable(h) + _CELL_PADDING)
                measured.append(col_min)
                header_floors.append(hdr_floor)

            total_min = sum(measured)

            # Scale-down path: too many/wide columns for the page
            if total_min >= avail_w:
                scale = avail_w / total_min
                result = []
                content_floors = []
                for i, m in enumerate(measured):
                    cf = _content_min_usable(headers[i]) + _CELL_PADDING
                    content_floors.append(cf)
                    # Floor = max of header_floor (header readable) and content_floor
                    # (no mid-word character breaks). content_floor is the binding constraint
                    # for wide columns containing long GRC terminology.
                    result.append(max(m * scale, header_floors[i], cf))
                # If floors still cause overflow, trim ONLY the headroom above content_floor
                # on wide columns. Never trim below content_floor — that causes char breaks.
                over = sum(result) - avail_w
                if over > 0.5:
                    wide_idx = [i for i in range(n) if _col_weight(headers[i]) >= 2.0]
                    # Headroom = what's above content_floor (safely trimmable)
                    trimmable = [max(0.0, result[i] - content_floors[i]) for i in wide_idx]
                    total_trim = sum(trimmable)
                    if total_trim > 0:
                        reduce = min(over, total_trim)
                        for j, i in enumerate(wide_idx):
                            result[i] -= (trimmable[j] / total_trim) * reduce
                    else:
                        # All columns are at their content_floor — must scale everything
                        # equally (rare: extremely wide tables). Accept some word-break risk.
                        scale2 = avail_w / sum(result)
                        result = [r * scale2 for r in result]
                return result

            # Normal path: distribute remaining space by content weight
            remaining = avail_w - total_min
            weights = [_col_weight(h) for h in headers]
            total_weight = sum(weights) or 1.0
            extras = [(w / total_weight) * remaining for w in weights]
            return [measured[i] + extras[i] for i in range(n)]

        lines = content.split('\n')
        i = 0
        last_pdf_heading = ''  # tracks the last heading for missing-header context
        last_pdf_section_heading = ''  # tracks the last ## section heading (parent context)
        
        while i < len(lines):
            line = lines[i].strip()
            
            if not line:
                i += 1
                continue
            
            # Skip separator lines
            if line == '---':
                story.append(Spacer(1, 0.2*inch))
                i += 1
                continue
            
            # Skip [SECTION] markers
            if line.strip() == '[SECTION]':
                story.append(Spacer(1, 0.15*inch))
                i += 1
                continue
            
            # Check if this is a table
            if line.startswith('|') and '|' in line[1:]:
                table_data = []
                expected_cols = 0
                while i < len(lines):
                    row_line = lines[i].strip()
                    if row_line.startswith('|') and row_line.endswith('|'):
                        if '---' not in row_line:  # Skip separator
                            cells = [c.strip() for c in row_line.split('|')[1:-1]]
                            if cells:
                                if expected_cols == 0:
                                    expected_cols = len(cells)
                                # Reverse column order for Arabic RTL
                                if is_arabic:
                                    cells = cells[::-1]
                                table_data.append(cells)
                        i += 1
                    elif not row_line:
                        # Blank line — peek ahead for table continuation
                        peek = i + 1
                        while peek < len(lines) and not lines[peek].strip():
                            peek += 1
                        if peek < len(lines):
                            peek_ln = lines[peek].strip()
                            if peek_ln.startswith('|') and peek_ln.endswith('|'):
                                peek_cells = [c.strip() for c in peek_ln.split('|')[1:-1]]
                                peek_next = lines[peek + 1].strip() if peek + 1 < len(lines) else ''
                                is_sep = peek_next.startswith('|') and '---' in peek_next
                                if is_sep and expected_cols > 0 and len(peek_cells) == expected_cols:
                                    i = peek + 2  # Skip duplicate header + separator
                                    continue
                                elif not is_sep and expected_cols > 0:
                                    i = peek
                                    continue
                        break
                    else:
                        break
                
                if table_data and len(table_data) >= 2:  # Need header + at least 1 data row
                    # ── Detect and inject missing table header (PDF path) ─────────────
                    # Uses same content-vs-label logic as _normalize_section so any
                    # table whose first row has long content (not short column labels)
                    # gets the correct header injected. Works for both digit-first rows
                    # and content-first rows (the real production case).
                    _PDF_COL_LABELS = {
                        '#','م','no','no.','phase','step','description','owner','deliverable',
                        'activity','responsible','accountable','consulted','informed','timeline',
                        'key deliverable','objective','target metric','target value',
                        'justification','timeframe','gap','priority','status',
                        'kpi','kpi description','formula','calculation formula',
                        'likelihood','impact','mitigation plan','factor','importance',
                        'initiative','expected deliverable','action','tool/system','output',
                        # Maturity / policy table headers
                        'dimension','maturity','current maturity','target maturity',
                        'current state','target state','current baseline','target',
                        'gap description','control area','activity / control area',
                        # Compliance / enforcement table headers
                        'nca ecc control','requirement','verification method','compliance owner',
                        'violation severity','consequence','escalation path',
                        'exception type','approval authority','maximum duration','review frequency',
                        'review type','frequency','trigger events','responsible',
                        'finding','severity','compliance status','control domain',
                        # KPI tables
                        'measurement method','reporting frequency','nca ecc alignment',
                        'calculation formula','tool/system',
                        # Roles / RACI
                        'role','authority','core duties','accountabilities',
                        'policy owner','it / security','business units','audit & compliance',
                        'executive / board',
                        # Generic label words
                        'item','detail','details','notes','field','value','type',
                        # Arabic equivalents
                        'المرحلة','الخطوة','الوصف','المسؤول','المخرج','المخرجات',
                        'النشاط','المحاسب','المستشار','المطلع','الجدول الزمني',
                        'الهدف','المقياس المستهدف','المبرر','الإطار الزمني',
                        'الفجوة','الأولوية','الحالة','المؤشر','وصف المؤشر',
                        'القيمة المستهدفة','صيغة الاحتساب','المبادرة',
                        'العامل','الأهمية','الخطر','الاحتمالية','التأثير','خطة التخفيف',
                        'البعد','مستوى النضج الحالي','مستوى النضج المستهدف',
                    }
                    _PDF_HDR_MAP = {
                        (5,'objective') : ['#','Objective','Target Metric','Justification','Timeframe'],
                        (4,'objective') : ['#','Objective','Target Metric','Justification'],
                        (3,'objective') : ['#','Objective','Details'],
                        (5,'الهدف')     : ['#','الهدف','المقياس المستهدف','المبرر','الإطار الزمني'],
                        (4,'الهدف')     : ['#','الهدف','المقياس المستهدف','المبرر'],
                        (5,'الأهداف')   : ['#','الهدف','المقياس المستهدف','المبرر','الإطار الزمني'],
                        (4,'الأهداف')   : ['#','الهدف','المقياس المستهدف','المبرر'],
                        (6,'kpi')       : ['#','KPI Description','Target Value','Calculation Formula','Justification','Timeframe'],
                        (5,'kpi')       : ['#','KPI Description','Target Value','Formula','Justification'],
                        (6,'مؤشر')      : ['#','وصف المؤشر','القيمة المستهدفة','صيغة الاحتساب','المبرر','الإطار الزمني'],
                        (5,'gap')       : ['#','Gap','Description','Priority','Status'],
                        (4,'gap')       : ['#','Gap','Description','Priority'],
                        (4,'الفجوة')    : ['#','الفجوة','الوصف','الأولوية'],
                        (5,'الفجوة')    : ['#','الفجوة','الوصف','الأولوية','الحالة'],
                        (5,'الفجوات')   : ['#','الفجوة','الوصف','الأولوية','الحالة'],
                        (4,'الفجوات')   : ['#','الفجوة','الوصف','الأولوية'],
                        (4,'initiative'): ['#','Initiative','Description','Expected Deliverable'],
                        (4,'مبادرة')    : ['#','المبادرة','الوصف','المخرج المتوقع'],
                        (5,'risk')      : ['#','Risk','Likelihood','Impact','Mitigation Plan'],
                        (4,'risk')      : ['#','Risk','Likelihood','Mitigation Plan'],
                        (4,'factor')    : ['#','Factor','Description','Importance'],
                        (3,'factor')    : ['Factor','Description','Importance'],
                        # Roadmap / implementation tables — first col is wide Initiative text,
                        # never '#' (that would collapse it to 20pt and break words).
                        (5,'roadmap')   : ['Activity','Owner','Accountable','Timeline','Key Deliverable'],
                        (4,'roadmap')   : ['Initiative','Description','Timeline','Expected Deliverable'],
                        (3,'roadmap')   : ['Initiative','Timeline','Expected Deliverable'],
                        # Maturity assessment tables
                        (5,'maturity')  : ['Dimension','Current Maturity','Target Maturity','Gap Description','Priority'],
                        (4,'maturity')  : ['Dimension','Current Maturity','Target Maturity','Gap Description'],
                        # KPI implementation guide tables (Step | Action | Tool/System | Owner | Output)
                        (5,'kpi guide')         : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'kpi guide')         : ['Step','Action','Owner','Output'],
                        (5,'assessment guide')  : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'assessment guide')  : ['Step','Action','Owner','Output'],
                        (5,'assessment')        : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'assessment')        : ['Step','Action','Owner','Output'],
                        (5,'implementation guide'): ['Phase','Step','Description','Owner','Deliverable'],
                        (5,'دليل التنفيذ')      : ['المرحلة','الخطوة','الوصف','المسؤول','المخرج'],
                        (5,'دليل التقييم')      : ['الخطوة','الإجراء','النظام/الأداة','المسؤول','المخرج'],
                        # Default fallbacks — use 'Item' not '#' so the first column
                        # gets proper content-width (weight 2.0) not narrow '#' (weight 0.5).
                        # The '#' default was causing any unrecognised table's first column
                        # to be rendered at ~20pt, breaking long text character-by-character.
                        (3,'default')   : ['Item','Description','Details'],
                        (4,'default')   : ['Item','Description','Details','Notes'],
                        (5,'default')   : ['Item','Description','Details','Notes','Status'],
                        (6,'default')   : ['#','Item','Detail 1','Detail 2','Detail 3','Status'],
                        # Workstream RACI — inject proper column headers when AI omits the header row
                        (7,'workstream'): ['Activity','Responsible','Accountable','Consulted','Informed','Timeline','Key Deliverable'],
                        (6,'workstream'): ['Activity','Responsible','Accountable','Consulted','Timeline','Key Deliverable'],
                        (7,'ورشة')      : ['النشاط','المسؤول','المحاسب','المستشار','المطلع','الجدول الزمني','المخرج الرئيسي'],
                        (6,'ورشة')      : ['النشاط','المسؤول','المحاسب','المستشار','الجدول الزمني','المخرج الرئيسي'],
                        # Phase/Roadmap tables — "Phase 1: Foundation", "Phase 2: Build", "Phase 3: Optimize"
                        (5,'phase')     : ['#','Activity','Owner','Timeline','Deliverable'],
                        (4,'phase')     : ['Activity','Owner','Timeline','Deliverable'],
                        (5,'foundation'): ['#','Activity','Owner','Timeline','Deliverable'],
                        (5,'build')     : ['#','Activity','Owner','Timeline','Deliverable'],
                        (5,'optimize')  : ['#','Activity','Owner','Timeline','Deliverable'],
                        # Pillar initiative tables — "Pillar 1: ...", "Pillar 2: ..."
                        (4,'pillar')    : ['#','Initiative','Description','Expected Deliverable'],
                        (3,'pillar')    : ['Initiative','Description','Expected Deliverable'],
                    }
                    _PDF_KW = ['objective','goal','الهدف','الأهداف','kpi','مؤشر',
                               'gap','الفجوة','الفجوات','initiative','مبادرة',
                               'factor','risk','roadmap','مخاطر',
                               'maturity','assessment','workstream','ورشة',
                               'phase','pillar','foundation','build','optimize',
                               'assessment guide','kpi guide','implementation guide',
                               'دليل التنفيذ','دليل التقييم']

                    def _pdf_is_col_label(t):
                        return t.lower().strip().strip('*# ') in _PDF_COL_LABELS or len(t.strip()) <= 3

                    # No-'#' header alternatives — used when col-0 data has long content
                    # that would be crammed into a narrow '#' column (20pt) → char-level wrapping.
                    _PDF_HDR_NONUM = {
                        (6,'kpi')       : ['KPI Description','Target Value','Calculation Formula','Justification','Timeframe','Source'],
                        (5,'kpi')       : ['KPI Description','Target Value','Calculation Formula','Justification','Timeframe'],
                        (4,'kpi')       : ['KPI Description','Target Value','Justification','Timeframe'],
                        (5,'objective') : ['Objective','Target Metric','Justification','Timeframe','Source'],
                        (4,'objective') : ['Objective','Target Metric','Justification','Timeframe'],
                        (3,'objective') : ['Objective','Target Metric','Justification'],
                        (5,'goal')      : ['Objective','Target Metric','Justification','Timeframe','Source'],
                        (4,'goal')      : ['Objective','Target Metric','Justification','Timeframe'],
                        (5,'gap')       : ['Gap','Description','Priority','Status','Owner'],
                        (4,'gap')       : ['Gap','Description','Priority','Status'],
                        (4,'initiative'): ['Initiative','Description','Expected Deliverable','Timeline'],
                        (3,'initiative'): ['Initiative','Description','Expected Deliverable'],
                        (5,'risk')      : ['Risk','Likelihood','Impact','Mitigation Plan','Owner'],
                        (4,'risk')      : ['Risk','Likelihood','Mitigation Plan','Owner'],
                        (4,'factor')    : ['Factor','Description','Importance','Owner'],
                        (3,'factor')    : ['Factor','Description','Importance'],
                        # Pillar initiative tables — no '#' variant
                        (4,'pillar')    : ['Initiative','Description','Expected Deliverable','Notes'],
                        (3,'pillar')    : ['Initiative','Description','Expected Deliverable'],
                        # Assessment / KPI guide tables — no '#' variant
                        (5,'assessment guide') : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'assessment guide') : ['Step','Action','Owner','Output'],
                        (5,'assessment')       : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'assessment')       : ['Step','Action','Owner','Output'],
                        (5,'kpi guide')        : ['Step','Action','Tool/System','Owner','Output'],
                        (4,'kpi guide')        : ['Step','Action','Owner','Output'],
                        (5,'implementation guide'): ['Phase','Step','Description','Owner','Deliverable'],
                        # Phase roadmap tables — no '#' variant
                        (4,'phase')     : ['Activity','Owner','Timeline','Deliverable'],
                        (3,'phase')     : ['Activity','Timeline','Deliverable'],
                        (4,'foundation'): ['Activity','Owner','Timeline','Deliverable'],
                        (4,'build')     : ['Activity','Owner','Timeline','Deliverable'],
                        (4,'optimize')  : ['Activity','Owner','Timeline','Deliverable'],
                        (4,'roadmap')   : ['Activity','Owner','Timeline','Deliverable'],
                    }

                    _fr = [re_pdf.sub(r'\*+','',str(c)).strip() for c in table_data[0]]
                    _non_empty = [c for c in _fr if c]
                    if _non_empty:
                        _label_n = sum(1 for c in _non_empty if _pdf_is_col_label(c))
                        _content_n = sum(1 for c in _non_empty if not _pdf_is_col_label(c) and len(c) > 8)
                        # Guard: if first row is ALREADY a column-label header (majority are labels),
                        # never inject — that would produce a phantom "# | Item | Detail 1…" data row.
                        _first_row_is_header = _label_n > len(_non_empty) / 2
                        if _content_n > _label_n and not _first_row_is_header:
                            _nc = len(_fr)
                            _mc = _nc  # meaningful col count (strip trailing empty)
                            while _mc > 0 and not _fr[_mc-1]: _mc -= 1
                            # Combine sub-heading + parent section heading so that
                            # Phase 1/2/3 tables inherit 'roadmap' context from '## 4. Implementation Roadmap'
                            _ctx = (last_pdf_heading + ' ' + last_pdf_section_heading).lower()
                            _injected = None
                            for _kw in _PDF_KW:
                                if _kw in _ctx:
                                    _injected = (_PDF_HDR_MAP.get((_nc, _kw)) or
                                                 _PDF_HDR_MAP.get((_mc, _kw)))
                                    if _injected: break
                            if not _injected:
                                _injected = (_PDF_HDR_MAP.get((_nc, 'default')) or
                                             _PDF_HDR_MAP.get((_mc, 'default')))
                            if _injected:
                                # ── Safety guard: never cram long col-0 text into a '#' column ──
                                # When AI omits the '#' column and puts KPI/objective names
                                # directly in col-0, the '#'-first injected header forces those
                                # long names into a 20pt column → character-level wrapping.
                                # Fix: if col-0 data rows have long content AND injected col-0
                                # is '#', swap in a nonum alternative (no '#' prefix).
                                _NARROW_HDR_VALS = {'#', 'م', 'no', 'no.', 'rn', 'رقم', 'n°'}
                                if _injected[0].strip().lower() in _NARROW_HDR_VALS:
                                    _col0_texts = [str(row[0]).strip() for row in table_data if row]
                                    _col0_avg = (sum(len(t) for t in _col0_texts) /
                                                 max(len(_col0_texts), 1))
                                    if _col0_avg > 20:
                                        # Try nonum alternative (same col count, no '#' col-0)
                                        _alt = None
                                        for _kw2 in _PDF_KW:
                                            if _kw2 in _ctx:
                                                _alt = (_PDF_HDR_NONUM.get((_nc, _kw2)) or
                                                        _PDF_HDR_NONUM.get((_mc, _kw2)))
                                                if _alt: break
                                        if _alt and len(_alt) == _nc:
                                            _injected = _alt
                                        else:
                                            # Fallback: drop '#' from col-0, shift labels left,
                                            # pad tail with empty string to preserve col count.
                                            _corrected = list(_injected[1:])
                                            while len(_corrected) < _nc:
                                                _corrected.append('')
                                            _injected = _corrected[:_nc]
                                table_data = [_injected] + table_data

                    # Create table with smart column widths
                    col_count = len(table_data[0]) if table_data else 1
                    
                    # Check if this is an implementation guidelines table (has Phase/Step columns)
                    header_row = [re_pdf.sub(r'\*+', '', str(c)).strip().lower() for c in table_data[0]] if table_data else []  # strip bold markers
                    # True implementation guide: Phase column is col 0 (Phase, Step, Desc, Owner, Deliverable)
                    # KPI assessment guide:      Step column is col 0  (Step, Action, Tool/System, Owner, Output)
                    # ── Column widths: use smart engine — no more magic-number branches ──
                    available_width = doc.width
                    col_widths = smart_col_widths(table_data, available_width)
                    # If table is empty / degenerate, fall back to equal distribution
                    if not col_widths:
                        col_widths = [available_width / max(col_count, 1)] * col_count

                    # ── FIX-A: correct column misalignment when header has '#' but data rows ──
                    # have one fewer column. E.g. 6-col header ['#','KPI Description',...] paired
                    # with 5-col data ['KPI Name','100%',...]. Data col-0 (KPI Name) would land
                    # in the '#' column (15pt) → character-level wrapping. Fix: prepend an empty
                    # '#' cell to any short data row whose col-0 contains long text.
                    if (table_data and len(table_data) > 1 and
                            re_pdf.sub(r'\*+','',str(table_data[0][0])).strip().lower()
                            in ('#','م','no','no.')):
                        _hdr_cols = len(table_data[0])
                        _fixed_rows = [table_data[0]]  # keep header unchanged
                        for _dr in table_data[1:]:
                            if (len(_dr) == _hdr_cols - 1 and _dr and
                                    len(str(_dr[0]).strip()) > 8):
                                # Data row is short by 1 and col-0 has real content
                                # → missing '#' value → prepend empty cell
                                _fixed_rows.append([''] + list(_dr))
                            else:
                                _fixed_rows.append(_dr)
                        if any(len(r) != len(table_data[r_i])
                               for r_i, r in enumerate(_fixed_rows)):
                            table_data = _fixed_rows
                            col_count = max(len(r) for r in table_data)
                            col_widths = smart_col_widths(table_data, available_width)
                            if not col_widths:
                                col_widths = [available_width / max(col_count, 1)] * col_count

                    # ── FIX-B: col-0 has main content despite '#' header ─────────────
                    # When the Big-4 synthesis step rewrites the objectives / KPI /
                    # initiative table and places the full descriptive text (e.g.
                    # "Establish Dedicated Cybersecurity Department") directly in the
                    # '#' column, that ~41pt column produces character-level word breaks
                    # (visible as "Estab lish D edica ted…" in the PDF).
                    # FIX-A only catches rows that are SHORT by one column; FIX-B catches
                    # the case where the row has the CORRECT column count but col-0
                    # contains prose instead of a row-number digit.
                    # Resolution: swap the '#' header for the content-first nonum
                    # alternative so col-0 inherits the proper wide column weight.
                    _col0_hdr_chk = re_pdf.sub(r'\*+', '', str(table_data[0][0])).strip().lower()
                    if (table_data and len(table_data) > 1 and
                            _col0_hdr_chk in ('#', 'م', 'no', 'no.')):
                        _data_col0_b = [str(row[0]).strip() for row in table_data[1:] if row]
                        _long_b = sum(
                            1 for t in _data_col0_b
                            if not re_pdf.match(r'^\s*\d{0,3}\s*$', t) and len(t) > 12)
                        if _data_col0_b and _long_b > len(_data_col0_b) * 0.4:
                            _nc_b = len(table_data[0])
                            _ctx_b = (last_pdf_heading + ' ' + last_pdf_section_heading).lower()
                            _alt_b = None
                            for _kw_b in _PDF_KW:
                                if _kw_b in _ctx_b:
                                    _candidate_b = _PDF_HDR_NONUM.get((_nc_b, _kw_b))
                                    if _candidate_b and len(_candidate_b) == _nc_b:
                                        _alt_b = _candidate_b
                                        break
                            if _alt_b:
                                table_data = [_alt_b] + list(table_data[1:])
                                col_count = max(len(r) for r in table_data)
                                col_widths = smart_col_widths(table_data, available_width)
                                if not col_widths:
                                    col_widths = [available_width / max(col_count, 1)] * col_count

                    # Wrap cell content in Paragraphs
                    # Scale font size to column count — more columns = tighter cells = smaller font
                    # but never below 8pt (below that ReportLab breaks words at character level)
                    if col_count >= 7:
                        _cell_font_size = 8.0

                        _cell_leading   = 11
                    elif col_count == 6:
                        _cell_font_size = 8.5
                        _cell_leading   = 12
                    else:
                        _cell_font_size = 9.0
                        _cell_leading   = 14
                    cell_style = ParagraphStyle(
                        'CellStyle', 
                        fontSize=_cell_font_size, 
                        leading=_cell_leading,
                        fontName=arabic_font_name if is_arabic else 'Helvetica',
                        alignment=TA_RIGHT if is_arabic else TA_LEFT,
                    )
                    header_cell_style = ParagraphStyle(
                        'HeaderCellStyle', 
                        fontSize=_cell_font_size, 
                        leading=_cell_leading, 
                        textColor=colors.white,
                        fontName=arabic_font_bold if is_arabic else 'Helvetica-Bold',
                        alignment=TA_RIGHT if is_arabic else TA_LEFT,
                    )
                    
                    wrapped_data = []
                    for row_idx, row in enumerate(table_data):
                        wrapped_row = []
                        for col_idx, cell in enumerate(row):
                            cell_text = str(cell)
                            # Process Arabic: reshape and per-cell-width bidi
                            if is_arabic and cell_text:
                                cw = col_widths[col_idx] if col_idx < len(col_widths) else text_width / len(row)
                                cell_text = process_arabic_table(cell_text, cw, font_size=9)
                            if row_idx == 0:  # Header row
                                wrapped_row.append(Paragraph(cell_text, header_cell_style))
                            else:
                                wrapped_row.append(Paragraph(cell_text, cell_style))
                        wrapped_data.append(wrapped_row)
                    
                    t = Table(wrapped_data, colWidths=col_widths)
                    t.setStyle(TableStyle([
                        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#1B2A4A')),
                        ('TEXTCOLOR', (0, 0), (-1, 0), colors.white),
                        ('ALIGN', (0, 0), (-1, -1), 'RIGHT' if is_arabic else 'LEFT'),
                        ('VALIGN', (0, 0), (-1, -1), 'TOP'),
                        ('FONTNAME', (0, 0), (-1, -1), arabic_font_name if is_arabic else 'Helvetica'),
                        ('FONTSIZE', (0, 0), (-1, -1), 9),
                        ('BOTTOMPADDING', (0, 0), (-1, 0), 10),
                        ('TOPPADDING', (0, 0), (-1, -1), 8),
                        ('BOTTOMPADDING', (0, 1), (-1, -1), 8),
                        # LEFT/RIGHT padding must match _CELL_PADDING/2 = 9pt so
                        # the smart engine's usable-width calculations stay accurate
                        ('LEFTPADDING',  (0, 0), (-1, -1), 9),
                        ('RIGHTPADDING', (0, 0), (-1, -1), 9),
                        ('BACKGROUND', (0, 1), (-1, -1), colors.HexColor('#FAFBFC')),
                        ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#D0D5DD')),
                        ('ROWBACKGROUNDS', (0, 1), (-1, -1), [colors.white, colors.HexColor('#F2F6FA')]),
                    ]))
                    story.append(t)
                    story.append(Spacer(1, 0.15*inch))
                continue
            
            # Handle markdown headings
            # IMPORTANT: Strip markdown prefix FIRST, then process Arabic
            # Check more specific headings first (#### before ### before ##)
            # CRITICAL: When AI writes "### KPIs: | # | KPI Description |..."
            # on ONE line, the table header is embedded in the heading text.
            # Split it out and re-inject so the table parser sees a proper header row.
            def _split_heading_table(raw_text):
                """Return (heading_text, table_line_or_None). Mirrors grc-markdown.js logic."""
                pipe_idx = raw_text.find('|')
                if pipe_idx > 0 and raw_text.count('|') >= 3:
                    heading_part = raw_text[:pipe_idx].rstrip(': \t')
                    table_part   = raw_text[pipe_idx:].strip()
                    return heading_part, table_part
                return raw_text, None

            if line.startswith('#### '):
                raw_text = line[5:]
                heading_txt, tbl_inject = _split_heading_table(raw_text)
                last_pdf_heading = heading_txt  # track for missing-header context
                text = process_arabic(heading_txt, arabic_font_bold, 14) if is_arabic else heading_txt
                story.append(Paragraph(text, heading2_style))
                if tbl_inject:
                    lines.insert(i + 1, tbl_inject)
            elif line.startswith('### '):
                raw_text = line[4:]
                heading_txt, tbl_inject = _split_heading_table(raw_text)
                last_pdf_heading = heading_txt
                text = process_arabic(heading_txt, arabic_font_bold, 14) if is_arabic else heading_txt
                story.append(Paragraph(text, heading2_style))
                if tbl_inject:
                    lines.insert(i + 1, tbl_inject)
            elif line.startswith('## '):
                raw_text = line[3:]
                heading_txt, tbl_inject = _split_heading_table(raw_text)
                last_pdf_heading = heading_txt
                last_pdf_section_heading = heading_txt  # ## = section level; used as parent ctx for sub-tables
                text = process_arabic(heading_txt, arabic_font_bold, 18) if is_arabic else heading_txt
                story.append(Paragraph(text, heading1_style))
                if tbl_inject:
                    lines.insert(i + 1, tbl_inject)
            elif line.startswith('# '):
                raw_text = line[2:]
                heading_txt, tbl_inject = _split_heading_table(raw_text)
                last_pdf_heading = heading_txt
                text = process_arabic(heading_txt, arabic_font_bold, 24) if is_arabic else heading_txt
                story.append(Paragraph(text, title_style))
                if tbl_inject:
                    lines.insert(i + 1, tbl_inject)
            elif line.startswith('> '):
                # Blockquote: collect consecutive > lines into one styled block
                bq_parts = [line[2:].strip()]
                while i + 1 < len(lines) and lines[i + 1].strip().startswith('> '):
                    i += 1
                    bq_parts.append(lines[i].strip()[2:].strip())
                bq_text = ' '.join(bq_parts)
                # Build inline-bold XML for ReportLab — use re_pdf (already imported)
                bq_fragments = re_pdf.split(r'\*\*(.+?)\*\*', bq_text)
                rl_text = ''
                for _bi, _bp in enumerate(bq_fragments):
                    _bp_safe = _bp.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
                    if _bi % 2 == 1:
                        rl_text += f'<b>{_bp_safe}</b>'
                    else:
                        rl_text += f'<i>{_bp_safe}</i>'
                bq_style = ParagraphStyle(
                    'BlockquoteStyle',
                    parent=styles['Normal'],
                    fontSize=10,
                    leading=15,
                    leftIndent=18  if not is_arabic else 0,
                    rightIndent=0  if not is_arabic else 18,
                    spaceBefore=8,
                    spaceAfter=8,
                    textColor=colors.HexColor('#2D3748'),
                    backColor=colors.HexColor('#F7F9FC'),
                    borderPadding=(6, 10, 6, 14),
                    fontName=arabic_font_name if is_arabic else 'Helvetica-Oblique',
                    alignment=TA_RIGHT if is_arabic else TA_LEFT,
                )
                if is_arabic:
                    bq_text_ar = process_arabic(bq_text, arabic_font_name, 10)
                    story.append(Paragraph(bq_text_ar, bq_style))
                else:
                    story.append(Paragraph(rl_text, bq_style))
                story.append(Spacer(1, 0.05 * inch))
            elif line.startswith('- ') or line.startswith('* ') or line.startswith('• '):
                raw_text = line[2:]
                if is_arabic:
                    text = process_arabic(raw_text, arabic_font_name, 11, extra_indent=20)
                    bullet_text = text + ' •'
                    story.append(Paragraph(bullet_text, bullet_style))
                elif '**' in raw_text:
                    # Bullet with inline bold — split on ** markers and build ReportLab XML
                    # so bold text is rendered properly instead of showing literal asterisks
                    # which can make the bold prefix appear to chop the word (Bug #5).
                    _bparts = re_pdf.split(r'\*\*(.+?)\*\*', raw_text)
                    _bfmt = ''
                    for _bi2, _bp2 in enumerate(_bparts):
                        _bp2s = _bp2.replace('&','&amp;').replace('<','&lt;').replace('>','&gt;')
                        if _bi2 % 2 == 1:
                            _bfmt += f'<b>{_bp2s}</b>'
                        else:
                            _bfmt += _bp2s
                    story.append(Paragraph('• ' + _bfmt, bullet_style))
                else:
                    bullet_text = '• ' + raw_text
                    story.append(Paragraph(bullet_text, bullet_style))
            elif len(line) > 2 and line[0].isdigit() and (line[1] == '.' or (len(line) > 2 and line[1].isdigit() and line[2] == '.')):
                # Numbered list
                num_match = re_pdf.match(r'^(\d+)\.\s*(.+)', line)
                if num_match:
                    num = num_match.group(1)
                    raw_text = num_match.group(2)
                    text = process_arabic(raw_text, arabic_font_name, 11, extra_indent=20) if is_arabic else raw_text
                    if is_arabic:
                        numbered_text = text + ' .' + num
                    else:
                        numbered_text = num + '. ' + text
                    story.append(Paragraph(numbered_text, numbered_style))
                else:
                    text = process_arabic(line, arabic_font_name, 11) if is_arabic else line
                    story.append(Paragraph(text, normal_style))
            elif line.startswith('**') and line.endswith('**'):
                raw_text = line[2:-2]
                # ── KPMG shaded panel for known callout labels ─────────────
                _rl = raw_text.strip().rstrip(':').lower()
                if _rl in _KPMG_CALLOUT_LABELS and i + 1 < len(lines):
                    _panel_body_lines = []
                    _j = i + 1
                    while _j < len(lines):
                        _pl = lines[_j].strip()
                        if not _pl:
                            _j += 1
                            continue
                        if (_pl.startswith('#') or
                                (_pl.startswith('**') and _pl.endswith('**')) or
                                _pl.startswith('|')):
                            break
                        _panel_body_lines.append(_pl)
                        _j += 1
                        break
                    _panel_body = ' '.join(_panel_body_lines)
                    try:
                        _panel = _make_kpmg_panel(raw_text, _panel_body, doc.width)
                        story.append(Spacer(1, 0.12*inch))
                        story.append(_panel)
                        story.append(Spacer(1, 0.08*inch))
                        i = _j
                        continue
                    except Exception as _pe:
                        print(f"KPMG panel (non-fatal): {_pe}", flush=True)
                text = process_arabic(raw_text, arabic_font_bold, 11) if is_arabic else raw_text
                story.append(Paragraph(f'<b>{text}</b>', callout_style))
            elif '**' in line:
                # Handle inline bold - strip ** markers, then process Arabic
                parts = re_pdf.split(r'\*\*(.+?)\*\*', line)
                formatted_parts = []
                for idx, part in enumerate(parts):
                    if idx % 2 == 1:  # Bold text
                        p = process_arabic(part, arabic_font_bold, 11) if is_arabic else part
                        formatted_parts.append(f'<b>{p}</b>')
                    else:
                        p = process_arabic(part, arabic_font_name, 11) if is_arabic else part
                        formatted_parts.append(p)
                formatted = ''.join(formatted_parts)
                story.append(Paragraph(formatted, normal_style))
            else:
                text = process_arabic(line, arabic_font_name, 11) if is_arabic else line
                story.append(Paragraph(text, normal_style))
            
            i += 1
        
        # ── Running header/footer on body pages (page 2+) ──────────────
        import datetime as _dt
        _today_footer = _dt.date.today().strftime('%d %B %Y')
        _doc_title_footer = (domain_pdf or filename.replace('_', ' ').title())
        _org_footer       = org_name_pdf if org_name_pdf != 'The Organization' else 'Mizan GRC'

        def _on_page(canvas_obj, doc_obj):
            """Draw header rule + footer on every page after cover."""
            if doc_obj.page < 2:
                return
            canvas_obj.saveState()
            _pw = A4[0]
            _lm = 1.5 * cm
            _rm = A4[0] - 1.5 * cm
            _line_y_top    = A4[1] - 1.4 * cm
            _line_y_bottom = 1.55 * cm

            # Header: thin navy rule + document title left, org name right
            canvas_obj.setStrokeColorRGB(0.106, 0.165, 0.290)  # #1B2A4A
            canvas_obj.setLineWidth(1.2)
            canvas_obj.line(_lm, _line_y_top, _rm, _line_y_top)
            canvas_obj.setFont('Helvetica', 7.5)
            canvas_obj.setFillColorRGB(0.106, 0.165, 0.290)
            canvas_obj.drawString(_lm, _line_y_top + 3, _doc_title_footer[:60])
            canvas_obj.drawRightString(_rm, _line_y_top + 3, _org_footer[:50])

            # Footer: thin rule + classification left, page number center, date right
            canvas_obj.setLineWidth(0.8)
            canvas_obj.line(_lm, _line_y_bottom, _rm, _line_y_bottom)
            canvas_obj.setFont('Helvetica', 7)
            canvas_obj.setFillColorRGB(0.44, 0.54, 0.63)
            canvas_obj.drawString(_lm, _line_y_bottom - 9, 'CONFIDENTIAL')
            canvas_obj.drawCentredString(_pw / 2, _line_y_bottom - 9, f'Page {doc_obj.page}')
            canvas_obj.drawRightString(_rm, _line_y_bottom - 9, _today_footer)
            canvas_obj.restoreState()

        # Build PDF
        doc.build(story, onFirstPage=_on_page, onLaterPages=_on_page)
        buffer.seek(0)
        
        from flask import send_file
        return send_file(
            buffer,
            mimetype='application/pdf',
            as_attachment=True,
            download_name=f'{filename}.pdf'
        )
        
    except ImportError as e:
        return jsonify({'error': f'PDF generation not available: {str(e)}'}), 500
    except Exception as e:
        print(f"PDF generation error: {str(e)}")
        import traceback
        traceback.print_exc()
        return jsonify({'error': f'PDF generation failed: {str(e)}'}), 500

@app.route('/api/set-language/<lang>')
def set_language(lang):
    """Set language preference."""
    session['lang'] = lang if lang in ['en', 'ar'] else 'en'
    return jsonify({'success': True, 'lang': session['lang']})

