@app.route('/api/awareness/modules')
@login_required
def api_awareness_modules():
    """Get awareness modules for a domain (includes GRC professional modules)."""
    try:
        domain = request.args.get('domain', 'Cyber Security')
        lang = request.args.get('lang', 'en')
        domain_code = DOMAIN_CODES.get(domain, 'cyber')
        
        modules = list(AWARENESS_MODULES.get(domain_code, {}).get(lang, AWARENESS_MODULES.get(domain_code, {}).get('en', [])))
        
        # Also include domain-relevant GRC professional modules
        grc_domain_relevance = {
            'cyber': ['grc_nca_frameworks', 'grc_iso27001', 'grc_nist_csf', 'grc_sama_framework', 'grc_incident_bcm', 'grc_cyber_gcc', 'grc_cyber_eu'],
            'data': ['grc_pdpl', 'grc_gdpr', 'grc_ndmo', 'grc_data_gcc', 'grc_data_us', 'grc_data_intl'],
            'ai': ['grc_eu_regulations', 'grc_sdaia_ai', 'grc_nist_ai_rmf', 'grc_iso42001', 'grc_ai_gcc'],
            'dt': ['grc_cobit_itil', 'grc_dt_ksa', 'grc_dt_gcc', 'grc_dt_eu', 'grc_dt_us'],
            'global': ['grc_iso27001', 'grc_gdpr', 'grc_eu_regulations', 'grc_coso_erm', 'grc_fundamentals', 'grc_sox_pci', 'grc_global_ksa', 'grc_global_gcc'],
            'erm': ['grc_coso_erm', 'grc_sama_framework', 'grc_iso31000', 'grc_erm_gcc', 'grc_erm_eu', 'grc_erm_us']
        }
        relevant_ids = grc_domain_relevance.get(domain_code, [])
        all_grc = AWARENESS_MODULES.get('grc_professional', {}).get(lang, AWARENESS_MODULES.get('grc_professional', {}).get('en', []))
        existing_ids = {m['id'] for m in modules}
        for gm in all_grc:
            if gm.get('id') in relevant_ids and gm.get('id') not in existing_ids:
                modules.append(gm)
        
        # Get user's completed modules
        conn = get_db()
        completed = conn.execute(
            'SELECT module_id, score, total, passed FROM awareness_scores WHERE user_id = ? AND domain = ?',
            (session['user_id'], domain)
        ).fetchall()
        
        completed_map = {r['module_id']: {'score': r['score'], 'total': r['total'], 'passed': r['passed']} for r in completed}
        
        # Add completion status to modules
        modules_with_status = []
        for m in modules:
            m_copy = dict(m)
            if m['id'] in completed_map:
                m_copy['completed'] = True
                m_copy['user_score'] = completed_map[m['id']]['score']
                m_copy['user_total'] = completed_map[m['id']]['total']
                m_copy['passed'] = bool(completed_map[m['id']]['passed'])
            else:
                m_copy['completed'] = False
            modules_with_status.append(m_copy)
        
        return jsonify({'success': True, 'modules': modules_with_status})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/avatar/<name>')
def serve_avatar(n):
    """Serve avatar image with flexible extension handling."""
    import os
    from flask import send_file
    avatar_dir = os.path.join(app.static_folder, 'avatars')
    base = n.split('.')[0]
    for ext in ['.png.jpeg', '.jpeg', '.jpg', '.png', '.webp']:
        fp = os.path.join(avatar_dir, base + ext)
        if os.path.exists(fp):
            return send_file(fp)
    fp = os.path.join(avatar_dir, n)
    if os.path.exists(fp):
        return send_file(fp)
    return '', 404


